import { G, T, A, O, P } from './domains.js';

export const part7 = [
  {id:757,domain:A,question:"What is the purpose of network access control (NAC)?",options:["Controlling exactly which individuals are permitted physical entry into the locked building that houses an organization's core network equipment typically enforced through badge readers, guards, and mantraps","A security solution that enforces policy-based control over devices attempting to connect to a network, checking compliance (patches, AV status) before granting access and can quarantine non-compliant devices","Limiting the total number of staff members who are formally granted network administrator-level account privileges across the whole company unrelated to whether those accounts' devices are compliant","Managing and throttling the total amount of internet bandwidth allocated to each individual company department or defined user group unrelated to whether a connecting device meets security requirements"],answer:1,explanation:"NAC solutions (Cisco ISE, Aruba ClearPass) check device posture (OS patch level, antivirus status, domain membership) before granting network access — non-compliant devices get placed in a quarantine VLAN with remediation access only, preventing unpatched/infected devices from reaching production networks.",optionExplanations:["This describes physical building access control for equipment rooms, not network admission control based on evaluated device compliance status.","NAC enforces security posture requirements at the network admission point, preventing devices that don't meet baseline security standards from accessing sensitive network resources.","Limiting how many administrator accounts exist is access management, distinct from endpoint posture checking or network admission control functionality.","Bandwidth throttling is a quality-of-service function, a separate network capability entirely from device-compliance-based network access control."]},
  {id:758,domain:O,question:"What is a security information event management (SIEM) use case?",options:["A commercial licensing tier that determines the maximum volume of raw log data a SIEM platform is contractually permitted to store per month billed monthly based on gigabytes ingested and retained","A predefined detection scenario or rule set within a SIEM designed to identify a specific type of security event or attack pattern, such as detecting impossible travel or brute force login attempts","The specific server hardware specifications an organization is required to purchase in order to physically run a SIEM platform on-site locally sized to handle the expected volume of incoming log data","A vendor support contract tier that defines exactly how quickly a SIEM provider must respond to submitted customer support tickets and requests outlined in the master services agreement signed at purchase"],answer:1,explanation:"Example use cases: 'Impossible Travel' (same user logs in from US then China within an hour), 'Brute Force Detection' (5+ failed logins in 5 minutes), 'Privilege Escalation' (standard user added to Domain Admins) — each use case translates a known attack pattern into correlation rules and alerts.",optionExplanations:["Storage licensing tiers are a commercial contract detail related to billing, not the analytical detection logic that a SIEM use case represents.","SIEM use cases operationalize threat detection by codifying known attack patterns and anomalies into specific, actionable correlation rules and alerts that the security team can tune and respond to.","Hardware procurement specifications are an infrastructure planning concern, entirely unrelated to the detection logic concept behind a SIEM 'use case.'","Support ticket response time commitments are a vendor service-level agreement term, not a technical SIEM detection concept applied to events."]},
  {id:759,domain:T,question:"What is a session fixation attack?",options:["The routine process software developers follow to find and repair ordinary software defects and bugs found within session management code during routine maintenance","An attack where an attacker sets or predicts a victim's session ID before authentication, then hijacks the session once the victim logs in using that known session ID","The administrative helpdesk task of manually restoring a user's session state after it was unexpectedly terminated by an application crash event so the user can resume.","A denial-of-service attack that deliberately overwhelms and exhausts the servers responsible for issuing brand new session tokens to users automatically."],answer:1,explanation:"If an application doesn't regenerate session IDs after login, an attacker can send a victim a link with a pre-set session ID (?PHPSESSID=attackerknown123) — once the victim logs in, the attacker uses that same session ID to access the authenticated session.",optionExplanations:["This describes a routine development and maintenance activity, not the deliberate attack technique that session fixation actually is.","Session fixation exploits applications that accept externally-supplied session identifiers without regenerating them post-authentication — the fix is always issuing a new session ID upon successful login.","Restoring a crashed user's session is a remediation and support activity performed by staff, not an exploitation technique like session fixation.","Session fixation is a hijacking technique that abuses a known session identifier, not an availability attack directed against session servers."]},
  {id:760,domain:P,question:"What is the role of a Chief Information Security Officer (CISO)?",options:["The staff member responsible for handling and resolving day-to-day IT helpdesk tickets and routine desktop support requests from end users escalating more complex tickets to senior technicians when needed","The senior executive responsible for establishing and maintaining the enterprise security vision, strategy, and program, aligning security initiatives with business objectives and managing organizational risk","The individual engineer personally responsible for writing and maintaining literally all of an organization's security-related source code alone leaving strategic planning and vendor management to other executives","The facilities manager responsible exclusively for overseeing the guards and physical locks that protect a company's office buildings with no authority over digital systems, networks, or data protection"],answer:1,explanation:"The CISO bridges the gap between technical security operations and executive/board-level business strategy — translating technical risk into business risk language, securing budget, and ensuring security supports rather than hinders business objectives.",optionExplanations:["Helpdesk ticket management is operational IT support work, far below the CISO's strategic, executive-level responsibility within the organization.","The CISO role is strategic and executive-level, focused on governance, risk management, and aligning the security program with overall business strategy and risk appetite — not day-to-day technical execution.","CISOs are executives who set strategy and policy for the whole organization; they don't typically write or personally maintain all security code themselves.","Physical facility security is one component, but the CISO role encompasses the entire information security program, spanning both digital and physical domains."]},
  {id:761,domain:A,question:"What is the function of a reverse proxy?",options:["A theoretical proxy server design concept that would supposedly route network traffic backward through previously recorded past network states, a concept with no basis in real protocol design","A server that sits in front of backend servers, forwarding client requests to them and returning responses, often providing load balancing, caching, SSL termination, and security filtering","A proxy server whose sole and only function is decrypting incoming encrypted traffic back into plainly readable plaintext, discarding the plaintext right afterward every time","A proxy server used exclusively by internal company employees to reach external websites and services on the public internet, and cannot receive any inbound connections at all"],answer:1,explanation:"Reverse proxies (NGINX, HAProxy) hide backend server details from clients, distribute load across multiple servers, cache static content, terminate SSL/TLS to offload encryption overhead, and can filter malicious requests (WAF functionality) before they reach application servers.",optionExplanations:["This is wordplay; 'reverse' refers to direction relative to a forward proxy, not any theoretical backward time-travel network concept.","Reverse proxies sit between clients and servers from the server side, providing centralized security, performance, and availability benefits that would be difficult to implement at each individual backend server.","Reverse proxies don't exist solely to decrypt traffic; SSL termination is only one optional function among several capabilities they can perform.","Forward proxies serve outbound client requests headed to external sites; reverse proxies instead serve inbound requests directed at backend servers."]},
  {id:762,domain:T,question:"What is a brute force attack?",options:["A physically forceful break-in attack that targets and ultimately destroys the locked door of an organization's own on-site server room, using a heavy battering ram or other similar forced-entry tool to gain access","An attack method that systematically attempts all possible password combinations or uses extensive wordlists until the correct credential is found, relying on computational power rather than vulnerability exploitation","The act of forcefully unplugging and physically disconnecting network cabling in order to intentionally disrupt connectivity to a targeted server, taking the service completely offline until restored","An attack that applies excessive physical pressure or force in an attempt to physically bypass a fingerprint or biometric door lock, pressing the sensor mechanically until it incorrectly grants access"],answer:1,explanation:"Online brute force attacks against login forms are typically slow and noisy (triggering lockouts), while offline brute force against captured password hashes can attempt billions of combinations per second using GPU clusters — strong, unique passwords and proper hashing (bcrypt, Argon2) are the primary defenses.",optionExplanations:["This isn't a physical break-in at all; it's a computational, algorithmic password-guessing technique performed over a network or offline.","Brute force attacks rely on trying many possibilities exhaustively, contrasting with attacks that exploit logic flaws or vulnerabilities — defenses include account lockout, rate limiting, and strong adaptive hashing functions.","Physically disconnecting cables would be a physical sabotage or availability act, unrelated to systematically guessing login credentials.","This describes a physical biometric bypass technique relying on brute physical force, not the computational brute force credential-guessing method."]},
  {id:763,domain:O,question:"What is the purpose of a runbook in security operations?",options:["A schedule document listing the shift assignments and working hours of every individual member of a company's security operations team published weekly by the operations manager for the department","A documented set of step-by-step procedures for responding to specific, recurring operational events or incidents, enabling consistent and efficient handling, often supporting automation","A physical logbook kept manually at a data center specifically to record server uptime and downtime readings by hand each day cross-referenced against a spreadsheet for monthly reporting","A financial ledger recording an organization's various security-related budget expenditures purely for internal accounting purposes and audits reviewed quarterly by finance during the annual budget season"],answer:1,explanation:"A phishing email runbook might specify: 1) Quarantine the email across all mailboxes, 2) Check if any users clicked the link, 3) Reset credentials for affected users, 4) Block the sender domain — having this codified means any analyst can respond consistently, and the steps can often be automated via SOAR platforms.",optionExplanations:["This isn't about staff shift scheduling at all; it's instead about documented, repeatable operational incident-response procedures used by analysts.","Runbooks standardize response actions for known scenarios, reducing response time variability and human error, and serving as the foundation for security orchestration and automated response (SOAR) playbooks.","Manual uptime logging by hand is a monitoring record-keeping task, distinct from the documented step-by-step response procedures a runbook contains.","A financial expenditure ledger for accounting is entirely unrelated to the security operational procedures that a runbook actually documents."]},
  {id:764,domain:A,question:"What is the principle behind a screened subnet (formerly DMZ) architecture?",options:["A network segment configured specifically to visually filter or block certain content from ever appearing on connected monitor display screens installed in conference rooms to block glare during video calls","A network segment positioned between the internal trusted network and the untrusted internet, hosting public-facing services while isolating them from the internal network if compromised","A dedicated subnet used solely to connect and centrally manage an organization's large-format video conference room display screens connected via a dedicated low-latency uplink to the main switch","A backup network segment kept entirely in reserve specifically to support disaster recovery failover operations, kept fully offline until an actual recovery event gets officially declared"],answer:1,explanation:"Web servers, mail servers, and DNS servers in a screened subnet are reachable from the internet but have restricted access to internal networks — if a public-facing server is compromised, the attacker still must breach another firewall layer to reach internal systems, limiting blast radius.",optionExplanations:["This is wordplay; 'screened' refers to network traffic filtering rules, not filtering visual content displayed on physical monitor screens.","Screened subnets implement defense-in-depth by isolating publicly accessible services from sensitive internal resources, ensuring compromise of an internet-facing system doesn't directly expose the internal network.","This isn't about video-conferencing display technology at all; it's a network architecture security zone specifically for public-facing services.","DR subnets serve business continuity failover purposes, a different architectural concern entirely from perimeter security segmentation of services."]},
  {id:765,domain:T,question:"What is a man-in-the-browser (MITB) attack?",options:["An attack that requires an attacker to be physically present sitting at the victim's own desk, using their computer and browser directly, making this fundamentally a physical, not remote, threat","A trojan-based attack that infects a web browser to intercept and manipulate communications between the user and web applications in real time, often used for financial fraud","A structured QA testing technique used by developers to check how a website visually renders across many different web browser vendors, rather than an actual exploitation technique","An attack that specifically targets and silently corrupts a user's synchronized browser bookmarks and previously saved history, leaving saved logins and favorite sites unusable"],answer:1,explanation:"MITB malware (like the Zeus banking trojan) injects malicious code into the browser process itself, allowing it to modify transaction details (e.g., changing the destination account number) after the user enters and confirms data but before it's transmitted — defeating even TLS encryption since the manipulation happens at the application layer inside the browser.",optionExplanations:["MITB doesn't require physical presence at the victim's desk at all; it's malware that infects the browser remotely over the network.","MITB attacks operate at the application layer within the browser process, making them effective even against TLS-protected connections since the data is manipulated after decryption but before display/transmission.","This isn't a QA cross-browser compatibility testing technique; it's malicious browser exploitation used for real-time financial transaction manipulation instead.","Bookmark and history corruption is unrelated; MITB instead targets live transaction and communication content within active browser sessions."]},
  {id:766,domain:G,question:"What is the purpose of input validation in secure coding?",options:["Confirming that the visual layout and color scheme of a web form's input fields appears aesthetically pleasing and clean to end users, with rounded corners and consistent spacing","Checking and sanitizing user-supplied data against expected formats, types, lengths, and ranges before processing it, preventing injection attacks and unexpected application behavior","Confirming that a specific user has correctly and completely typed their own full legal name into a single designated form field rather than checking any other field an application might receive","Counting the total number of individual input fields present on a given web application's overall submission form layout with no regard for what data those fields actually contain"],answer:1,explanation:"Proper input validation (allowlisting expected characters/formats rather than blocklisting known-bad patterns) is the first line of defense against SQL injection, XSS, command injection, and buffer overflows — it should be performed server-side since client-side validation can be bypassed.",optionExplanations:["Visual form design and color scheme is a UX concern, entirely unrelated to the security validation that input validation actually performs.","Input validation is a fundamental secure coding practice that prevents malicious or malformed data from reaching application logic, databases, or the OS layer where it could cause harm.","Checking one specific name field is a narrow example of a single check; input validation applies broadly to all untrusted data an application receives.","Counting form fields is a UI layout concern unrelated to the actual security validation applied to the data submitted through those fields."]},
  {id:767,domain:O,question:"What is the purpose of vulnerability scanning frequency requirements in compliance frameworks?",options:["Vulnerability scanning is only ever legally required a single time.","Many compliance frameworks (PCI DSS, etc.) mandate regular.","Compliance frameworks generally treat vulnerability scanning frequency.","Scans should be executed only a single time per year."],answer:1,explanation:"PCI DSS requires quarterly external vulnerability scans by an Approved Scanning Vendor (ASV) plus scans after any significant network change — this regular cadence catches newly disclosed CVEs and configuration drift that a one-time assessment would miss.",optionExplanations:["A single scan performed only at deployment becomes outdated quickly as new vulnerabilities are disclosed and configurations continue to change.","Regular scanning cadences are explicitly mandated by frameworks like PCI DSS because the threat landscape and environment both change continuously, requiring ongoing verification rather than point-in-time assessment.","Compliance frameworks specifically define minimum scanning frequencies as concrete, mandatory audit requirements, not as optional best-practice suggestions.","Annual-only scanning confined to one maintenance window leaves long gaps where new vulnerabilities go undetected, failing most compliance frequency requirements."]},
  {id:768,domain:T,question:"What is a clickjacking attack?",options:["An attack that steals computer mice", "A UI redress attack where attackers trick users into clicking on something different from what they perceive, often using transparent or disguised overlay frames to hijack clicks for unintended actions", "A method for tracking ad clicks","An attack that disables mouse clicking"],answer:1,explanation:"An attacker overlays an invisible iframe of a legitimate page (e.g., a 'delete my account' or 'transfer funds' button) on top of an enticing decoy page — the user thinks they're clicking the decoy but actually clicks the hidden legitimate control, performing an unintended action.",optionExplanations:["This isn't about hardware theft; it's a UI manipulation web attack.","Clickjacking exploits how browsers render overlapping/transparent content, tricking users into performing actions they didn't intend — defenses include X-Frame-Options headers and frame-busting scripts.","Ad click tracking is a legitimate analytics function, unrelated to this malicious UI deception technique.","This doesn't disable clicking; it redirects the intent/target of legitimate clicks."]},
  {id:769,domain:A,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["A trusted software application for managing passwords","A dedicated hardware chip that securely generates, stores, and manages cryptographic keys, providing hardware-based security functions like secure boot verification and disk encryption key protection","A trusted list of approved software vendors","A module that monitors network traffic for trust violations"],answer:1,explanation:"TPM chips store the encryption keys used by BitLocker/FileVault in hardware isolated from the OS, perform secure boot integrity measurements (detecting bootkit/rootkit tampering), and resist extraction even with physical access — Windows 11 requires TPM 2.0 partly for this hardware-rooted security.",optionExplanations:["TPM is a hardware chip, not a software application.","TPM provides a hardware root of trust that's significantly more resistant to tampering and key extraction than software-only key storage, underpinning features like secure boot and full-disk encryption key protection.","This isn't a vendor allowlist; TPM is a cryptographic hardware security module.","Network traffic monitoring is a different security function from TPM's cryptographic key management role."]},
  {id:770,domain:P,question:"What is the purpose of a security control matrix or crosswalk?",options:["A physical matrix display in the SOC","A document mapping security controls across multiple frameworks or standards (e.g., NIST 800-53 to ISO 27001) to show equivalencies, simplifying compliance with multiple overlapping requirements","A matrix for tracking employee performance reviews","A network topology diagram"],answer:1,explanation:"Organizations subject to multiple frameworks (e.g., a healthcare company needing HIPAA and PCI DSS compliance) use crosswalks to identify where a single implemented control satisfies requirements across frameworks, avoiding duplicate work and demonstrating comprehensive compliance efficiently.",optionExplanations:["This isn't physical hardware; it's a documentation/mapping tool.","Control crosswalks/matrices reduce compliance overhead by identifying overlap between frameworks, letting organizations implement once and map to multiple regulatory or standards requirements.","Performance reviews are HR functions, unrelated to compliance control mapping.","Network diagrams show infrastructure topology, a different artifact from compliance control mapping."]},
  {id:771,domain:T,question:"What is a fileless malware attack?",options:["Malware that doesn't require any storage space","Malicious activity that operates primarily in memory, using legitimate system tools (like PowerShell or WMI) rather than writing executable files to disk, making it harder to detect with traditional file-based antivirus","Malware specifically targeting cloud file storage","An attack that deletes all files on a system"],answer:1,explanation:"Fileless malware leverages 'living off the land' techniques — using PowerShell, WMI, or registry-based persistence — to execute malicious code entirely in memory, evading signature-based AV that scans files on disk, and often disappearing after a reboot, complicating forensic analysis.",optionExplanations:["Fileless doesn't mean zero storage usage; it means avoiding traditional executable files to evade file-based detection.","Fileless techniques exploit trust in legitimate, signed system binaries (LOLBins) to execute malicious logic without ever writing a detectable malicious file, requiring behavioral/memory-based detection (EDR) rather than signature scanning.","Cloud file storage targeting describes a different attack category, not the fileless execution technique.","Fileless malware doesn't necessarily delete files; the term refers to its own execution method, not its payload behavior."]},
  {id:772,domain:O,question:"What is the purpose of a Security Orchestration, Automation, and Response (SOAR) platform?",options:["A platform for managing physical security guards' schedules","A platform that integrates security tools, automates repetitive response tasks via playbooks, and orchestrates workflows across the security stack to speed up incident response and reduce analyst workload","A platform for orchestral music used in SOC ambiance","A platform exclusively for vulnerability scanning"],answer:1,explanation:"SOAR platforms (Splunk SOAR, Palo Alto XSOAR) connect to SIEM, EDR, firewalls, and ticketing systems, executing automated playbooks (e.g., automatically isolating an infected host, blocking a malicious IP across all firewalls, and opening a ticket) in seconds rather than the minutes/hours manual response would take.",optionExplanations:["This isn't about physical guard scheduling; SOAR is a technical security operations tool.","SOAR addresses analyst fatigue and response time by automating well-understood, repetitive tasks, freeing analysts to focus on complex investigation and decision-making for novel threats.","This is wordplay; SOAR has nothing to do with music.","Vulnerability scanning is one possible integration but SOAR's core function is broader orchestration and automated response across the security toolchain."]},
  {id:773,domain:A,question:"What is the difference between full disk encryption (FDE) and file-level encryption?",options:["There is no meaningful difference","FDE encrypts an entire storage volume including the OS, applications, and all files as a single unit, while file-level encryption selectively encrypts individual files or folders, allowing more granular access control","File-level encryption is always faster than FDE","FDE only works on solid-state drives"],answer:1,explanation:"FDE (BitLocker, FileVault) protects data at rest if a device is lost/stolen since the entire drive is unreadable without the decryption key, but offers no protection once the OS is running and the user is authenticated — file-level encryption can keep specific sensitive files protected even from other authenticated users on the same system.",optionExplanations:["These are distinct approaches with different security properties, performance characteristics, and use cases.","FDE provides device-loss protection (encrypting everything at the volume level), while file-level encryption provides granular, persistent protection for specific sensitive data even during normal system operation by other users.","Performance varies by implementation; FDE with hardware acceleration can often outperform software file-level encryption.","FDE works on both HDDs and SSDs, though SSD-specific considerations like wear-leveling and TRIM exist."]},
  {id:774,domain:T,question:"What is a credential stuffing attack?",options:["Forcing too many credentials into a single login form field","An automated attack using lists of previously breached username/password pairs (often from unrelated breaches) to attempt logins on other services, exploiting password reuse across sites","Stuffing a server with fake credentials to confuse attackers","An attack that physically overloads authentication servers"],answer:1,explanation:"Because many users reuse passwords across services, attackers take credentials leaked in one breach (e.g., a gaming site) and test them en masse against unrelated high-value targets (banking, email) using automated tools — MFA and breached-password screening (checking against Have I Been Pwned-style databases) are key defenses.",optionExplanations:["This isn't about form field overflow; it's automated credential reuse testing across services.","Credential stuffing succeeds specifically because of widespread password reuse — defenses include MFA, CAPTCHA, rate limiting, and proactively checking new passwords against known breach databases.","This isn't a defensive deception technique; it's a real automated attack against authentication systems.","This is an automated login attempt attack, not a physical resource exhaustion attack."]},
  {id:775,domain:G,question:"What is the purpose of separation of duties as a security control?",options:["Physically separating employees into different buildings","Dividing critical tasks or responsibilities among multiple individuals so that no single person can complete a sensitive process alone, reducing fraud and error risk","Separating IT staff by their preferred programming languages","Requiring employees to take separate lunch breaks"],answer:1,explanation:"Example: the person who requests a wire transfer cannot also approve it, and the person who approves it cannot also execute it — this requires collusion between multiple people to commit fraud, significantly raising the difficulty and detection likelihood compared to a single insider acting alone.",optionExplanations:["Physical building separation isn't the mechanism; it's about dividing process responsibilities, regardless of location.","Separation of duties is a foundational fraud-prevention control, ensuring critical or sensitive processes require multiple people, making unilateral malicious or erroneous action much harder.","Programming language preference is irrelevant to this security control concept.","Lunch scheduling is unrelated to separation of duties in critical business processes."]},
  {id:776,domain:O,question:"What is a security baseline configuration?",options:["The lowest acceptable security budget","A documented, standardized minimum security configuration for a system or device type, against which deployed systems are compared to detect unauthorized changes or configuration drift","A baseline measurement of network bandwidth","An initial password set during system installation"],answer:1,explanation:"Security baselines (CIS Benchmarks, DISA STIGs) define settings like disabled unnecessary services, required password policies, and audit logging configuration — automated tools (SCAP scanners) regularly check deployed systems against the baseline, flagging any drift for remediation.",optionExplanations:["Budget is a financial concept, unrelated to technical configuration standards.","Baselines establish the expected secure state for systems, enabling automated drift detection and ensuring consistency across an organization's fleet of similar systems.","Bandwidth measurement is network performance monitoring, a different concept from configuration security baselines.","Initial passwords are one setting among many; baselines comprehensively define the full secure configuration state."]},
  {id:777,domain:T,question:"What is an evil twin attack?",options:["An attack performed by two coordinated attackers", "A rogue wireless access point set up to mimic a legitimate network's SSID, tricking users into connecting so the attacker can intercept their traffic","A malware variant that creates a duplicate of itself","An attack targeting backup/twin data centers"],answer:1,explanation:"An attacker sets up an AP broadcasting the same SSID as a legitimate network (e.g., 'Airport_WiFi') often with a stronger signal — victims' devices auto-connect to the familiar name, allowing the attacker to perform MITM attacks, capture credentials, or serve malicious content.",optionExplanations:["'Evil twin' refers to the rogue AP mimicking the legitimate one, not coordinated human attackers.","Evil twin attacks exploit user trust in familiar network names (SSIDs) and devices' tendency to auto-connect to previously known networks, enabling traffic interception without the victim's awareness.","This is a wireless network attack, not malware self-replication.","This targets wireless client devices, not redundant data center infrastructure."]},
  {id:778,domain:A,question:"What is the purpose of micro-segmentation in a data center network?",options:["Using smaller network cables","Creating granular security zones around individual workloads or applications (often within a single VLAN/subnet), enforcing strict policy-based communication rules between them, typically used in zero trust architectures","Dividing a data center into smaller physical buildings","Reducing the number of servers in a data center"],answer:1,explanation:"Unlike traditional VLAN segmentation which creates broad zones, micro-segmentation (using tools like VMware NSX or Illumio) can restrict communication down to the individual VM/container level — even systems on the same subnet must have explicit policy permission to communicate, dramatically limiting lateral movement if one workload is compromised.",optionExplanations:["Cable size is a physical layer concern unrelated to logical network segmentation.","Micro-segmentation extends segmentation principles to a much finer granularity than traditional network zones, directly supporting zero trust's 'never trust, always verify' approach by requiring explicit policy for any east-west traffic.","Physical building division is a different (and impractical) concept; micro-segmentation is a logical/software-defined control.","Server consolidation is a capacity/efficiency concern, unrelated to micro-segmentation's security purpose."]},
  {id:779,domain:O,question:"What is the purpose of a post-incident review (lessons learned) meeting?",options:["To assign blame to the team member who caused the incident","A structured review conducted after incident resolution to analyze what happened, evaluate the effectiveness of the response, and identify improvements to processes, tools, or training to prevent recurrence","To celebrate the incident response team's efforts","To immediately close the incident ticket without further analysis"],answer:1,explanation:"Effective lessons-learned meetings follow a blameless post-mortem approach, focusing on systemic and process improvements (e.g., 'why did detection take 6 hours?' leads to better alerting) rather than individual blame, which encourages honest disclosure of mistakes that improves future response.",optionExplanations:["Blameless post-mortems are the recommended practice specifically because blame culture suppresses honest reporting and learning.","Lessons-learned reviews are a critical feedback loop in the incident response lifecycle (NIST's IR process explicitly includes this phase), turning each incident into an opportunity to strengthen defenses and response capability.","While team recognition can be positive, the primary purpose is analytical improvement, not celebration.","Skipping analysis would forfeit the value of the incident as a learning opportunity, contrary to IR best practice."]},
  {id:780,domain:T,question:"What is the purpose of a logic bomb?",options:["A bomb threat made via a phone system","Malicious code intentionally inserted into a system that lies dormant until triggered by a specific condition (date, event, or action), at which point it executes a harmful payload","A type of brute-force password cracking tool","An attack that physically destroys network hardware"],answer:1,explanation:"A classic example: a disgruntled employee plants code that deletes critical database tables if their employee ID is removed from the payroll system (indicating termination) — logic bombs are particularly dangerous insider threats because they can remain undetected for long periods before triggering.",optionExplanations:["This is a software-based attack technique, not a physical threat or communication.","Logic bombs are characterized by their conditional trigger and dormancy — they're frequently associated with insider threats who have legitimate code access and can embed the malicious logic into systems they're trusted to maintain.","This isn't a password cracking technique; it's a dormant, conditionally-triggered malicious code payload.","Logic bombs are software attacks against data/systems, not physical hardware destruction (though some could trigger physical damage indirectly, that's not the defining characteristic)."]},
  {id:781,domain:G,question:"What is the purpose of a security awareness training program?",options:["Training only the IT security team on new tools","An ongoing program educating all employees about security threats (phishing, social engineering, safe data handling) and organizational policies, reducing human-factor risk which is a leading cause of breaches","A one-time training given only during new hire onboarding","Training employees exclusively on physical fire safety"],answer:1,explanation:"Since human error and social engineering are involved in the majority of breaches, ongoing security awareness training (phishing simulations, periodic refreshers, role-based training) is one of the highest-ROI security investments — a single onboarding session is quickly forgotten without reinforcement.",optionExplanations:["Awareness training targets all employees since everyone is a potential attack vector (phishing, social engineering), not just security specialists.","Continuous, organization-wide training directly addresses the human element, which remains one of the most exploited attack vectors despite technical controls.","One-time onboarding training has limited long-term retention; effective programs require ongoing reinforcement (e.g., quarterly phishing simulations).","Fire safety is physical safety training, a separate topic from cybersecurity awareness."]},
  {id:782,domain:O,question:"What is the purpose of a digital forensic disk image (bit-for-bit copy)?",options:["A photograph of the physical hard drive","An exact, sector-by-sector duplicate of a storage device, including deleted files, slack space, and unallocated space, preserving the original evidence in an unaltered state for examination","A compressed backup of only active files","A summary report of disk usage statistics"],answer:1,explanation:"Forensic imaging tools (FTK Imager, dd) create a verified (hash-matched) bit-for-bit copy so investigators can analyze a working copy while the original remains pristine and unaltered — write blockers are used during imaging to prevent any modification to the source device, preserving evidentiary integrity.",optionExplanations:["This isn't a literal photograph; it's a data-level exact duplication.","Bit-for-bit imaging captures everything including deleted/recoverable data and unallocated space, which standard file backups would miss, and preserves original evidence integrity for legal admissibility.","Active-file-only backups would miss deleted file remnants and forensic artifacts that are often critical to an investigation.","A usage summary report lacks the actual data needed for detailed forensic examination."]},
  {id:783,domain:T,question:"What is an XML External Entity (XXE) injection attack?",options:["An attack that injects XML formatting errors","An attack exploiting vulnerable XML parsers that process external entity references, potentially allowing attackers to read local files, perform SSRF, or cause denial of service","An attack that converts XML files to JSON maliciously","A network attack targeting XML-based routing protocols"],answer:1,explanation:"Vulnerable XML parsers that process DOCTYPE declarations with external entities can be exploited with payloads like <!ENTITY xxe SYSTEM 'file:///etc/passwd'> to read arbitrary local files, or to make the server perform SSRF requests to internal systems — disabling external entity processing in the parser is the primary defense.",optionExplanations:["This isn't about formatting errors; it's a parser vulnerability allowing malicious entity resolution.","XXE specifically abuses the XML standard's external entity feature, which many parsers process by default — leading to file disclosure, SSRF, or DoS if not explicitly disabled.","Format conversion is unrelated; XXE exploits parsing behavior, not data transformation.","This is an application-layer vulnerability in XML processing, not a network routing protocol attack."]},
  {id:784,domain:A,question:"What is the function of an Intrusion Prevention System (IPS) compared to an IDS?",options:["IPS and IDS are identical technologies with different names","An IPS actively blocks or prevents detected malicious traffic in real time (inline), while an IDS only detects and alerts on suspicious activity without taking automatic blocking action","IPS only works on wireless networks while IDS works on wired networks","IDS is always more accurate than IPS"],answer:1,explanation:"IDS is deployed out-of-band (monitoring a copy of traffic via a SPAN/mirror port), so it can alert but not block in real time, while IPS is deployed inline (directly in the traffic path), allowing it to drop malicious packets immediately — the tradeoff is that IPS false positives can disrupt legitimate traffic, while IDS false positives are just noisy alerts.",optionExplanations:["IDS and IPS differ fundamentally in deployment (out-of-band vs inline) and response capability (alert-only vs active blocking).","The key distinction is active prevention (inline blocking) versus passive detection (alerting only) — many products now offer both modes (IDS/IPS) configurable per deployment need.","Both technologies can be deployed on wired or wireless networks; the distinction is about response action, not network medium.","Accuracy depends on tuning and detection method, not which mode (IDS vs IPS) is used — both face the same detection accuracy challenges."]},
  {id:785,domain:P,question:"What is the purpose of a data retention policy?",options:["A policy ensuring data is never deleted","A policy defining how long different types of data must be kept and when it should be securely destroyed, balancing legal/regulatory requirements, business needs, and risk reduction from holding unnecessary data","A policy for backing up data daily","A policy restricting who can create new data"],answer:1,explanation:"Data retention policies specify, for example, that financial records must be kept 7 years (tax requirements) while old marketing emails can be deleted after 90 days — minimizing unnecessarily retained data reduces breach impact (less data to steal) and reduces storage/compliance costs, while still meeting legal hold requirements.",optionExplanations:["Retention policies specifically define when data SHOULD be deleted, not indefinite retention, which itself increases risk and storage costs.","Effective retention policies balance competing needs: legal/regulatory minimums, business utility, and the security principle of minimizing data exposure by not retaining what's no longer needed.","Backup frequency is an operational/availability concern, distinct from how long data should ultimately be retained or destroyed.","Retention policies govern data lifecycle/destruction, not data creation access permissions."]},
  {id:786,domain:T,question:"What is a race condition vulnerability?",options:["A vulnerability that only affects racing/gaming applications","A flaw occurring when the outcome of a process depends on the timing or sequence of uncontrollable events, which an attacker can exploit by manipulating timing to cause unintended behavior, such as Time-of-Check to Time-of-Use (TOCTOU) issues","A vulnerability causing systems to run faster than intended","An attack that races to crack passwords before lockout"],answer:1,explanation:"TOCTOU race conditions occur when a security check (e.g., verifying file permissions) and the actual use of that resource happen at different times — an attacker can swap the resource between the check and use (e.g., replacing a validated file with a malicious symlink) to bypass the security control.",optionExplanations:["This is a generic software vulnerability class, not specific to gaming applications despite the name.","Race conditions exploit the gap between when a condition is checked and when it's acted upon, allowing attackers to manipulate system state in that window — careful use of atomic operations and locking mechanisms prevents this.","Race conditions are about timing-dependent vulnerabilities, not literal execution speed increases.","This isn't about competing with lockout timers; it's about exploiting timing gaps in security checks within software logic."]},
  {id:787,domain:O,question:"What is a key performance indicator (KPI) used to measure SOC effectiveness?",options:["The number of coffee breaks taken by analysts","Metrics such as Mean Time to Detect (MTTD) and Mean Time to Respond (MTTR), which measure how quickly a SOC identifies and responds to security incidents, indicating operational efficiency","The total number of firewalls deployed","The number of employees in the organization"],answer:1,explanation:"MTTD (time from compromise to detection) and MTTR (time from detection to containment/resolution) are industry-standard SOC metrics — reducing these numbers through better tooling, automation, and process directly correlates with reduced breach impact and cost, since dwell time strongly influences damage extent.",optionExplanations:["This is unrelated to operational security performance measurement.","MTTD and MTTR are widely recognized as the most meaningful SOC performance metrics because they directly measure the speed of the detection-to-response pipeline, which correlates strongly with breach impact.","Firewall count is an infrastructure inventory metric, not a measure of SOC operational effectiveness.","Headcount is an organizational metric unrelated to demonstrating SOC detection/response capability."]},
  {id:788,domain:T,question:"What is a supply chain attack in the context of software development?",options:["An attack on physical shipping and logistics companies","An attack that compromises a trusted third-party component, library, update mechanism, or vendor in the software development/distribution pipeline to distribute malware to downstream users","An attack that disrupts product manufacturing","An attack targeting only hardware supply chains"],answer:1,explanation:"The SolarWinds attack compromised the build pipeline to insert malicious code into legitimate signed software updates, which were then trusted and installed by thousands of organizations — supply chain attacks are particularly dangerous because they exploit the inherent trust relationship between software vendors and their customers.",optionExplanations:["While the term originates from physical logistics, in cybersecurity it refers to the software/component delivery pipeline, not physical shipping.","Software supply chain attacks exploit trust in dependencies, build systems, or update mechanisms — a compromise upstream affects every downstream consumer of that software, creating massive blast radius from a single point of compromise.","This isn't about physical manufacturing; it specifically concerns software development and distribution processes.","Supply chain attacks span both hardware (e.g., implanted chips) and software (compromised code/updates), though software supply chain attacks have been more prevalent recently."]},
  {id:789,domain:A,question:"What is the purpose of DNS Security Extensions (DNSSEC)?",options:["Encrypting all DNS query traffic for confidentiality","Adding cryptographic signatures to DNS records to verify their authenticity and integrity, protecting against DNS spoofing and cache poisoning attacks by allowing resolvers to validate that responses haven't been tampered with","Speeding up DNS resolution times","Replacing DNS entirely with a new protocol"],answer:1,explanation:"DNSSEC uses a chain of trust with digital signatures (RRSIG records) from the root zone down to individual domains, allowing validating resolvers to cryptographically verify that a DNS response genuinely came from the authoritative source and wasn't altered in transit — note DNSSEC provides integrity/authenticity, not confidentiality (DNS queries remain visible; that's addressed separately by DNS over HTTPS/TLS).",optionExplanations:["DNSSEC provides authenticity and integrity, not confidentiality — queries are still visible in plaintext; DoH/DoT address the encryption gap.","DNSSEC's core purpose is enabling cryptographic validation of DNS data, directly countering cache poisoning and spoofing attacks that exploit DNS's original lack of authentication.","DNSSEC adds cryptographic overhead and can actually slightly increase response sizes/processing, rather than speeding up resolution.","DNSSEC is an extension that adds security features to the existing DNS protocol, not a complete replacement."]},
  {id:790,domain:G,question:"What is the difference between a vulnerability and an exploit?",options:["They are synonyms with no meaningful difference","A vulnerability is a weakness or flaw in a system that could potentially be exploited, while an exploit is the actual code, technique, or method used to take advantage of that vulnerability","An exploit is always more severe than a vulnerability","A vulnerability only exists in software, while an exploit only exists in hardware"],answer:1,explanation:"A vulnerability (e.g., an unpatched buffer overflow flaw, CVE-2024-XXXX) is the underlying weakness; the exploit is the working proof-of-concept or weaponized code that actually triggers and abuses that flaw to achieve a malicious outcome — a vulnerability can exist without a known exploit yet (theoretical risk) until someone develops one.",optionExplanations:["These terms describe distinct, related but separate concepts in the vulnerability lifecycle.","This distinction matters practically: vulnerability management tracks weaknesses to patch, while exploit availability (especially public/weaponized exploits) significantly raises urgency since the barrier to attack drops dramatically.","Severity is independent of whether something is labeled vulnerability vs exploit; a vulnerability can be critical even without a public exploit yet.","Both vulnerabilities and exploits can apply to software or hardware; the distinction is about flaw vs. the method of abuse, not the affected medium."]},
  {id:791,domain:O,question:"What is threat hunting?",options:["Hunting for new vendors to purchase threat intelligence from","A proactive security practice where analysts actively search for hidden threats or indicators of compromise within a network that have evaded existing automated detection tools, rather than waiting for alerts","A physical security patrol of server rooms","Hunting down employees who violate security policy"],answer:1,explanation:"Threat hunters form hypotheses (e.g., 'could an attacker be using PsExec for lateral movement undetected?') and proactively query logs, endpoint telemetry, and network data to test them, often uncovering sophisticated or long-dwelling threats that signature-based and rule-based detection missed entirely.",optionExplanations:["This isn't about vendor procurement; it's an active, analyst-driven detection methodology.","Threat hunting assumes that determined attackers may already be inside undetected and proactively searches for subtle evidence rather than passively waiting for automated alerts, addressing detection gaps in reactive security models.","This is a cybersecurity analytical practice, not physical security patrol activity.","This isn't about disciplinary action against employees; it's about searching for malicious actors/activity within the technical environment."]},
  {id:792,domain:T,question:"What is a privilege escalation attack?",options:["An attack that increases a company's security budget","A technique where an attacker who has gained limited access to a system exploits a vulnerability or misconfiguration to gain higher-level permissions than originally granted, such as moving from standard user to administrator/root","Promoting an employee to a higher position", "An attack that escalates the volume of network traffic"],answer:1,explanation:"Vertical privilege escalation moves from a lower privilege level to a higher one (user to admin), often via unpatched kernel exploits or misconfigured services, while horizontal escalation accesses another user's resources at the same privilege level — both are critical steps attackers take after initial foothold to achieve their objectives.",optionExplanations:["Budget is a business/financial concept, unrelated to technical access escalation.","Privilege escalation is a critical phase in the attack chain, allowing attackers to move from limited initial access to full system/domain control, often by exploiting unpatched vulnerabilities or misconfigurations.","This describes legitimate HR promotion, not unauthorized technical access escalation.","This isn't a traffic volume attack; it's about gaining unauthorized elevated system permissions."]},
  {id:793,domain:A,question:"What is the purpose of redundant array of independent disks (RAID) in the context of availability?",options:["RAID is used only for data encryption","A storage technology that combines multiple physical disks to provide data redundancy, improved performance, or both, helping ensure availability if one disk fails","RAID prevents all forms of data loss including ransomware","RAID is a backup replacement requiring no other data protection"],answer:1,explanation:"RAID 1 (mirroring) and RAID 5/6 (striping with parity) allow a system to continue operating and data to remain accessible even if one (or more, depending on RAID level) physical disk fails — but RAID is not a backup, since it doesn't protect against accidental deletion, ransomware encryption, or site-level disasters that backups and DR plans address.",optionExplanations:["RAID is unrelated to encryption; it's purely a storage redundancy/performance technology.","RAID directly supports the availability pillar of the CIA triad by allowing continued operation through disk-level hardware failures, though it addresses only this specific failure mode.","RAID has no protection against ransomware, logical corruption, or accidental deletion — those changes get written/mirrored across all disks identically, making proper backups still essential.","RAID is explicitly not a substitute for backups since it doesn't protect against logical data loss, deletion, or site disasters — separate backup and DR strategies remain necessary."]},
  {id:794,domain:T,question:"What is a directory traversal (path traversal) attack?",options:["An attack on physical building directories", "An attack exploiting insufficient input sanitization to access files and directories outside the intended restricted directory, often using sequences like '../' to navigate the file system", "A phone book scanning technique","An attack that traverses network routing tables"],answer:1,explanation:"Example: a vulnerable file download feature accepting ?file=report.pdf could be exploited with ?file=../../../../etc/passwd to access files far outside the intended download directory — proper input validation, allowlisting, and running with least-privilege file system permissions are key defenses.",optionExplanations:["This is a digital file system exploitation technique, not related to physical building navigation.","Path traversal exploits applications that build file paths from user input without properly restricting access to a designated directory, allowing attackers to read (or sometimes write) arbitrary files on the server.","This isn't related to phone directories; it's a web/file system security vulnerability.","This targets the file system hierarchy of a server, not network routing infrastructure."]},
  {id:795,domain:P,question:"What is the purpose of a Statement of Work (SOW) in vendor security engagements?",options:["A statement listing only the vendor's marketing claims","A formal document detailing the specific scope, deliverables, timeline, responsibilities, and terms of a vendor engagement, ensuring both parties have clear, agreed-upon expectations","A statement of the vendor's annual revenue","A general non-disclosure agreement template"],answer:1,explanation:"For a penetration test engagement, the SOW would specify exact systems in scope, testing methodology, deliverable format (report structure), timeline, and payment terms — providing a contractual basis for what work will be performed and preventing scope disputes after the engagement begins.",optionExplanations:["Marketing claims aren't the purpose; an SOW is a binding scope and deliverables document.","SOWs establish clear, mutually-agreed expectations for vendor engagements, reducing ambiguity and providing a reference point if disputes arise about what was actually agreed to be delivered.","Financial information about the vendor is unrelated to defining the scope of a specific engagement.","NDAs are a separate, distinct legal document focused on confidentiality, not on the scope and deliverables of the work itself."]},
  {id:796,domain:T,question:"What is typosquatting?",options:["A competitive typing speed contest","Registering domain names that are intentional misspellings or variations of legitimate, popular domains to capture mistyped traffic, often for phishing or malvertising purposes","A vulnerability in autocorrect software","An attack against domain name registrars"],answer:1,explanation:"An attacker might register 'gooogle.com' or 'arnazon.com' to capture users who mistype the intended URL — visitors might be served phishing pages mimicking the legitimate site, malicious ads, or have the domain sold back to the legitimate company at inflated prices.",optionExplanations:["This isn't a recreational activity; it's a malicious domain registration technique.","Typosquatting exploits common typing errors to redirect unsuspecting users to malicious or monetized look-alike domains, capitalizing on the high traffic volume of popular sites.","This isn't an autocorrect software flaw; it's deliberate exploitation of human typing mistakes via domain registration.","This isn't an attack on registrars themselves; it's the malicious use of legitimate domain registration services."]},
  {id:797,domain:O,question:"What is the purpose of an after-action report following a security incident?",options:["A report used only for insurance claims","A formal document summarizing the incident timeline, response actions taken, root cause, impact, and recommendations for improvement, serving as an official record and input for process improvement","A report listing all employees who worked overtime","A daily status report sent during active business operations"],answer:1,explanation:"After-action reports are more formal and comprehensive than lessons-learned meeting notes, often required for compliance/legal purposes and executive reporting — they document what happened, why, the response effectiveness, and concrete remediation action items with owners and deadlines.",optionExplanations:["While insurance claims may reference it, the AAR's primary purpose is comprehensive incident documentation and process improvement, with broader uses beyond insurance.","AARs create an official, comprehensive record that supports compliance requirements, legal needs, executive communication, and most importantly, drives concrete improvements to prevent recurrence.","Overtime tracking is an HR/payroll concern, unrelated to incident documentation.","AARs are produced after incident resolution as a retrospective document, not a real-time operational status update."]},
  {id:798,domain:A,question:"What is the purpose of an Application Programming Interface (API) gateway in security architecture?",options:["A gateway used only for physical building access","A centralized entry point for API traffic that enforces authentication, rate limiting, request validation, and monitoring policies before requests reach backend microservices","A gateway that translates programming languages","A backup system for API documentation"],answer:1,explanation:"API gateways (Kong, Apigee, AWS API Gateway) centralize cross-cutting security concerns — API key/OAuth token validation, rate limiting to prevent abuse, request/response transformation, and logging — so individual microservices don't each need to reimplement these controls, while also providing a single point for monitoring and threat detection across all API traffic.",optionExplanations:["This is a software/network architecture component, unrelated to physical access control.","API gateways centralize security enforcement for distributed microservice architectures, providing consistent authentication, authorization, and abuse prevention without burdening each individual service with redundant security logic.","API gateways manage traffic and policy enforcement, not language translation/compilation.","This is an active traffic management/security component, not a documentation backup system."]},
  {id:799,domain:T,question:"What is a deauthentication attack against wireless networks?",options:["An attack that prevents users from ever connecting to WiFi", "An attack sending spoofed deauthentication frames to forcibly disconnect a client from a wireless access point, often used to capture WPA handshakes for offline cracking or to facilitate evil twin attacks", "A legitimate network administration tool for managing connections", "An attack against wired Ethernet authentication"],answer:1,explanation:"Because 802.11 management frames were historically unauthenticated/unencrypted, an attacker can spoof deauth frames appearing to come from the AP, forcing a client to disconnect and reconnect — capturing the WPA/WPA2 4-way handshake during reconnection for offline password cracking, or as a denial-of-service/precursor to an evil twin attack. 802.11w (Protected Management Frames) mitigates this.",optionExplanations:["Deauth attacks force temporary, targeted disconnections rather than permanently preventing any future connection.","This attack exploits the historical lack of authentication on 802.11 management frames, enabling both DoS and as a stepping stone to credential capture or MITM attacks via forced reconnection.","While legitimate deauth frames exist for normal disconnection, this attack uses spoofed frames maliciously without authorization, distinguishing it from legitimate network management.","This specifically targets 802.11 wireless protocols' management frame handling, not wired Ethernet authentication mechanisms."]},
  {id:800,domain:G,question:"What is the purpose of the CIA triad in information security?",options:["A reference to the Central Intelligence Agency's security standards","A foundational model representing the three core objectives of information security: Confidentiality, Integrity, and Availability, used to guide security policy and control selection","A triad of three required security certifications","A model describing three types of cyberattacks"],answer:1,explanation:"Confidentiality ensures data is only accessible to authorized parties (encryption, access control), Integrity ensures data hasn't been improperly altered (hashing, digital signatures), and Availability ensures systems/data are accessible when needed (redundancy, DDoS protection) — virtually every security control can be mapped to supporting one or more of these three objectives.",optionExplanations:["This is purely a naming coincidence; the CIA triad is unrelated to the intelligence agency.","The CIA triad is the most fundamental conceptual framework in security, used to evaluate risks and justify controls by asking which of the three objectives a given threat or control affects.","This isn't about certifications; it's a conceptual security objectives framework.","The triad describes security goals/objectives to protect, not categories of attacks (though attacks can be classified by which CIA principle they violate)."]},
  {id:801,domain:O,question:"What is the purpose of network traffic baselining?",options:["Establishing a fixed maximum bandwidth limit","Establishing a profile of what 'normal' network traffic patterns look like (volume, protocols, destinations, timing) so that anomalies and deviations can be more easily detected","Setting the lowest acceptable network speed","A one-time network performance test during installation"],answer:1,explanation:"Once a baseline is established (e.g., normal traffic to a specific server averages 50GB/day on HTTPS), anomaly detection tools can flag deviations like a sudden 500GB outbound transfer at 3 AM as suspicious — without a baseline, abnormal activity may blend into the noise of 'normal' unanalyzed traffic.",optionExplanations:["Baselining is about understanding typical patterns for anomaly detection, not setting hard bandwidth caps.","Baselines provide the reference point necessary for behavioral/anomaly-based detection — without knowing what's normal, it's very difficult to algorithmically identify what's abnormal or suspicious.","This isn't about minimum speed requirements; it's about characterizing typical traffic behavior.","Effective baselining is ongoing and continuously updated, since 'normal' traffic patterns evolve over time as business needs change."]},
  {id:802,domain:T,question:"What is a DNS tunneling attack?",options:["An attack that physically taps into DNS server fiber optic cables", "A technique encoding data (such as command-and-control traffic or exfiltrated data) within DNS queries and responses, exploiting the fact that DNS traffic is often allowed through firewalls with minimal inspection", "A method to speed up DNS resolution","An attack that corrupts DNS zone transfer files"],answer:1,explanation:"Because DNS is essential for normal operation and often permitted outbound with limited inspection, attackers encode malware C2 commands or stolen data into DNS query subdomains (e.g., stolen-data-chunk1.attacker-domain.com) — DNS tunneling tools like Iodine or DNSCat2 can establish a covert communication channel that bypasses traditional firewall/proxy controls.",optionExplanations:["This is a logical/protocol-level technique, not physical infrastructure tampering.","DNS tunneling exploits the trust and minimal inspection typically given to DNS traffic to covertly transmit data, making it an effective technique for C2 communication and data exfiltration that evades many traditional network controls.","Tunneling adds overhead and complexity, making it slower than normal DNS resolution, not faster.","This is about covert data channels within DNS query/response traffic, not corrupting legitimate zone transfer data."]},
  {id:803,domain:A,question:"What is the purpose of a load balancer in availability architecture?",options:["A device that physically weighs server hardware", "A system that distributes incoming network traffic across multiple servers to optimize resource use, maximize throughput, minimize response time, and ensure no single server becomes a point of failure", "A tool used only for testing server capacity limits","A device that reduces the total number of servers needed"],answer:1,explanation:"Load balancers (F5, AWS ELB, NGINX) distribute traffic using algorithms like round-robin or least-connections, and perform health checks to automatically route traffic away from failed/unhealthy servers — this provides both performance benefits and availability resilience since the failure of one backend server doesn't cause an outage.",optionExplanations:["This is wordplay on 'load'; it refers to network/computational traffic distribution, not physical weight.","Load balancers improve both performance (distributing demand) and availability (automatic failover from unhealthy nodes), making them a critical component of resilient, scalable architectures.","While load testing can use similar traffic patterns, the load balancer's primary production purpose is ongoing traffic distribution, not testing.","Load balancers often work with multiple servers to provide redundancy; reducing server count would actually reduce the availability benefits they provide."]},
  {id:804,domain:O,question:"What is the purpose of conducting a business impact analysis (BIA)?",options:["Analyzing only the financial profitability of a business unit","A process identifying and evaluating the potential effects of disruptions to critical business operations, helping prioritize recovery efforts and determine acceptable downtime (RTO) and data loss (RPO) targets","Analyzing employee job satisfaction","A one-time technical penetration test report"],answer:1,explanation:"A BIA identifies critical business processes (e.g., order processing, payment systems), quantifies the impact of their disruption over time (financial loss, reputational damage, regulatory penalties), and uses this analysis to set RTO/RPO targets that then drive disaster recovery and business continuity planning priorities and budget allocation.",optionExplanations:["BIA considers broader business continuity impact, not solely financial profitability metrics.","BIA is foundational to business continuity/disaster recovery planning — it provides the data-driven justification for RTO/RPO targets and prioritizes which systems need the most robust (and costly) resilience investments.","Employee satisfaction is an HR metric, unrelated to business continuity impact analysis.","BIA is a business continuity planning process, not a technical security testing activity like a penetration test."]},
  {id:805,domain:T,question:"What is a SQL injection second-order attack?",options:["A SQL injection attack that occurs exactly twice","An attack where malicious input is stored safely at first (e.g., in a database) but later retrieved and used in a different, vulnerable SQL query without proper sanitization, triggering the injection at a delayed point","An attack targeting the second database server in a cluster","A backup SQL injection technique used if the first fails"],answer:1,explanation:"Example: a user registers with a username containing SQL metacharacters that pass initial input validation (since it's just stored as a string), but later, when an admin panel queries 'SELECT * FROM logs WHERE user=' + storedUsername without parameterization, the injection executes — the delayed execution path makes second-order injection harder to detect with simple input testing.",optionExplanations:["'Second-order' refers to the delayed execution path, not the number of occurrences.","Second-order SQL injection is dangerous specifically because the initial input handling may appear safe, while the vulnerability surfaces later when that stored data is used unsafely in a different context/query.","This isn't about targeting specific database server instances; it's about the timing/path of when malicious input triggers the injection.","This describes a distinct attack technique based on delayed exploitation, not a fallback method."]},
  {id:806,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["Assessing only the financial cost of privacy software","A systematic process evaluating how a new project, system, or process collects, uses, and protects personal data, identifying privacy risks before implementation to ensure compliance and minimize harm","A performance review for the privacy officer","An assessment conducted only after a data breach occurs"],answer:1,explanation:"PIAs (required under GDPR as DPIAs for high-risk processing) are conducted proactively during system design — they identify what personal data will be collected, why, how it will be protected, and whether less privacy-invasive alternatives exist, embodying the privacy-by-design principle rather than retrofitting privacy after deployment.",optionExplanations:["PIA evaluates privacy risk comprehensively, not narrowly focused on software costs.","PIAs operationalize 'privacy by design' by requiring risk evaluation before systems are built/deployed, when changes are far cheaper to make than after a system handling personal data is already in production.","This isn't an HR performance evaluation; it's a risk assessment of a system or process design.","PIAs are explicitly proactive/preventive assessments conducted before implementation, not reactive breach investigations."]},
  {id:807,domain:T,question:"What is an ARP cache poisoning attack?",options:["Physically damaging network router hardware","An attack where an attacker sends falsified ARP messages to associate their MAC address with the IP address of another host (often the default gateway), enabling traffic interception via man-in-the-middle positioning","An attack that corrupts DNS server cache entries","A technique to clear browser cache remotely"],answer:1,explanation:"Because ARP has no built-in authentication, an attacker can broadcast spoofed ARP replies claiming their MAC address corresponds to the gateway's IP — victim devices update their ARP cache and send traffic intended for the gateway to the attacker instead, who can then intercept, modify, or relay it (MITM) — Dynamic ARP Inspection (DAI) on switches is a key defense.",optionExplanations:["ARP poisoning is a logical/protocol attack, not physical hardware damage.","ARP's lack of authentication is the root vulnerability exploited — attackers can freely associate any MAC with any IP in victims' ARP caches, enabling local network traffic interception.","This targets the local network's ARP protocol/Layer 2, distinct from DNS cache poisoning which operates at a different layer/protocol.","This isn't about browser cache; ARP poisoning operates at the network/data link layer of local network communication."]},
  {id:808,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["A CDN exists purely for content licensing purposes","A geographically distributed network of servers caching and delivering content closer to users, which can also absorb and mitigate large-scale DDoS attacks due to its distributed capacity and provide WAF capabilities at the edge","A CDN that only delivers video content","A network used exclusively for internal corporate communications"],answer:1,explanation:"CDNs like Cloudflare and Akamai distribute massive amounts of capacity globally, which can absorb volumetric DDoS attacks that would overwhelm a single origin server — many CDNs also offer integrated WAF and bot mitigation services at the edge, filtering malicious traffic before it ever reaches the origin infrastructure.",optionExplanations:["Licensing is a separate business/legal concern; CDN's technical function relates to content delivery and security.","Beyond performance benefits, CDNs provide significant security value through distributed capacity (DDoS absorption) and edge security services (WAF, bot management) that protect origin infrastructure.","CDNs deliver various content types (web pages, images, video, APIs), not exclusively video.","CDNs are specifically designed for external, public-facing content delivery to end users across the internet, not internal-only communications."]},
  {id:809,domain:O,question:"What is the purpose of an incident severity classification system?",options:["Classifying incidents based only on the attacker's nationality","A standardized framework for categorizing incidents by their potential impact and urgency (e.g., Critical, High, Medium, Low), guiding appropriate resource allocation, escalation procedures, and response timelines","Classifying incidents alphabetically by name","A system used only for compliance reporting, not actual response"],answer:1,explanation:"Severity classification (often based on factors like data sensitivity affected, system criticality, and scope) ensures a ransomware attack on the primary domain controller gets immediate all-hands response while a single isolated phishing email triggers standard, less urgent handling — without this triage, organizations risk either under-responding to critical incidents or wasting resources over-responding to minor ones.",optionExplanations:["Attacker attribution isn't a factor in severity classification; impact and urgency are the key criteria.","Severity classification enables proportional, efficient resource allocation — ensuring the most critical incidents receive immediate executive attention and resources while less severe ones follow standard procedures.","Classification is based on impact/urgency criteria, not alphabetical organization, which would be meaningless for prioritization.","Severity classification directly drives real-time operational response decisions (escalation, resource allocation), not merely after-the-fact compliance documentation."]},
  {id:810,domain:T,question:"What is a watering hole versus spear phishing — what's the key distinguishing factor?",options:["There is no difference between these two attacks","Spear phishing directly targets specific individuals via deceptive communications (email), while a watering hole attack compromises a third-party site the targets are known to visit, waiting for them to come to the attacker rather than reaching out directly","Watering hole attacks only target government websites","Spear phishing is always less effective than watering hole attacks"],answer:1,explanation:"Spear phishing is an active, direct approach (crafting a convincing email to a specific person), while watering hole is a passive, indirect approach (compromising a site and waiting) — attackers may choose watering hole when direct targeting (email/social engineering) is difficult due to a hardened target who is unlikely to fall for direct phishing attempts.",optionExplanations:["These attacks have fundamentally different methodologies and threat models, despite both aiming at specific targets.","The key distinction is direct outreach (spear phishing) versus indirect compromise-and-wait (watering hole) — this matters for defense, since watering hole attacks bypass email security controls entirely by exploiting trusted third-party browsing.","Watering hole attacks can target any site frequented by the intended victims — industry forums, vendor sites, news outlets — not exclusively government sites.","Effectiveness depends on context; watering hole attacks can be highly effective specifically against targets resistant to direct phishing, while spear phishing is highly effective against less security-aware targets — neither is universally superior."]},
  {id:811,domain:G,question:"What is the principle of least functionality in system hardening?",options:["Configuring systems to use the least amount of electricity","Configuring a system to provide only the essential capabilities required for its function, disabling or removing unnecessary services, ports, protocols, and software to reduce the attack surface","Limiting how many users can access a system simultaneously","Reducing the physical size of server hardware"],answer:1,explanation:"A web server hardened with least functionality would have unnecessary services (FTP, Telnet, unused database engines) disabled, unused ports closed, and unneeded software uninstalled — every running service is a potential vulnerability and attack vector, so removing what isn't needed directly shrinks the attack surface.",optionExplanations:["This is about functional capability minimization for security, not power consumption.","Least functionality is a core hardening principle alongside least privilege — fewer running services and open ports mean fewer potential vulnerabilities for attackers to exploit.","User count limiting is a capacity/licensing concern, not the security hardening principle of minimizing system capabilities.","Physical hardware size is unrelated to the software/service configuration hardening principle."]},
  {id:812,domain:O,question:"What is the purpose of file integrity monitoring (FIM)?",options:["Monitoring how full a file storage disk is","A security control that tracks and alerts on unauthorized changes to critical system files, configuration files, or directories by comparing current file hashes/attributes against a known-good baseline","Monitoring file download speeds","A backup tool that copies files to a secondary location"],answer:1,explanation:"FIM tools (Tripwire, OSSEC) calculate cryptographic hashes of critical files (system binaries, configuration files like /etc/passwd) and alert when changes are detected — since malware and attackers often modify system files for persistence or to disable security controls, unexpected changes are a strong indicator of compromise.",optionExplanations:["Disk capacity monitoring is a different operational concern from detecting unauthorized file changes.","FIM provides change detection for critical files specifically as a tamper/compromise indicator — many compliance frameworks (PCI DSS) explicitly require FIM on systems handling sensitive data.","Download speed monitoring is a performance metric, unrelated to integrity verification.","Backup is data protection through copying, distinct from FIM's purpose of detecting unauthorized modifications."]},
  {id:813,domain:T,question:"What is a downgrade attack in the context of cryptographic protocols?",options:["An attack that physically downgrades server hardware specifications","An attack that forces a system to use a weaker, older, or less secure version of a protocol or cipher suite (such as forcing TLS 1.0 instead of TLS 1.3), exploiting weaknesses in the older standard","An attack that reduces an employee's account privileges","A social engineering attack targeting IT downgrades during budget cuts"],answer:1,explanation:"The POODLE attack exploited downgrade behavior to force connections to fall back to SSL 3.0, which had known vulnerabilities, even when both client and server supported more secure TLS versions — defenses include disabling legacy protocol/cipher support entirely and implementing protocol version pinning where possible (e.g., TLS_FALLBACK_SCSV).",optionExplanations:["This is a protocol-level attack on cryptographic negotiation, not physical hardware specification changes.","Downgrade attacks specifically target the negotiation phase of cryptographic protocols, forcing fallback to weaker, exploitable versions — disabling legacy protocol support is the primary mitigation.","This isn't about user account privilege changes; it's about cryptographic protocol version manipulation.","This is a technical cryptographic attack, not a social engineering or budget-related concept despite the similar word 'downgrade.'"]},
  {id:814,domain:A,question:"What is the purpose of geofencing in mobile device security?",options:["Building a physical fence around a data center","A security control that uses GPS or location data to restrict or trigger specific actions based on a device's physical location, such as disabling certain features outside an approved geographic area","Encrypting GPS coordinate data only","A fence used to block wireless signals"],answer:1,explanation:"Organizations might configure MDM policies to automatically lock a device or disable camera/data access when it leaves an approved geographic boundary (e.g., a hospital's campus), or conversely trigger enhanced security requirements when a device is detected in a high-risk country — geofencing adds a location-based contextual layer to access and security policies.",optionExplanations:["This is a software/policy-based location control, not physical perimeter fencing.","Geofencing enables location-aware security policies, allowing organizations to apply different security postures or restrictions based on where a device physically is, adding context to risk-based access decisions.","Geofencing uses location data to trigger policy actions; it's not specifically about encrypting the coordinate data itself.","This is unrelated to RF signal blocking (which would be a Faraday cage); geofencing is a software-based location policy mechanism."]},
  {id:815,domain:O,question:"What is the purpose of conducting regular access reviews (user access recertification)?",options:["Reviewing only new employee access during onboarding","A periodic process where managers or system owners verify that users' current access rights are still appropriate and necessary for their job role, identifying and removing excessive or unused permissions (privilege creep)","Reviewing the physical appearance of access badges","A one-time review conducted only during a security audit"],answer:1,explanation:"Privilege creep occurs as employees change roles over time, often accumulating access rights from previous positions that are never revoked — regular (e.g., quarterly) access reviews catch this drift, ensuring the principle of least privilege is maintained over time rather than only at initial provisioning.",optionExplanations:["Access reviews specifically focus on existing, ongoing access for current employees, not just new hire onboarding.","Regular recertification directly counters privilege creep, ensuring access rights remain aligned with current job responsibilities over time rather than accumulating unchecked.","This is about logical access permissions, not physical badge appearance/condition.","Effective access governance requires ongoing periodic reviews, not just point-in-time audit-driven checks, to catch drift as it occurs."]},
  {id:816,domain:T,question:"What is a Business Email Compromise (BEC) attack?",options:["Any email sent from a business account","A sophisticated social engineering attack where attackers impersonate executives or trusted business partners via email to trick employees into making fraudulent wire transfers or revealing sensitive information","An attack that physically compromises business email servers","A spam filtering technique used by businesses"],answer:1,explanation:"BEC attacks often involve researching an organization (via LinkedIn, press releases) to identify the right executive to impersonate, then sending urgent, plausible requests (e.g., 'I need this wire transfer processed immediately, I'm in a meeting') to finance staff — BEC causes billions in losses annually and often bypasses technical controls since it relies purely on social engineering rather than malware.",optionExplanations:["BEC refers specifically to a targeted fraud technique, not just any business-related email.","BEC is highly effective and costly because it exploits human trust and urgency rather than technical vulnerabilities, often bypassing spam filters since the emails contain no malicious links or attachments — just compelling social engineering text.","This isn't a server compromise technique; it's primarily a social engineering/impersonation attack via email content.","This describes a defensive technology, the opposite of the BEC attack technique itself."]},
  {id:817,domain:A,question:"What is the purpose of an air-gapped network?",options:["A network that uses only wireless connections", "A network that is physically isolated from unsecured networks, including the internet, with no physical or wireless connection, used to protect highly sensitive systems from remote attacks", "A network with extra space between server racks for cooling","A backup network used during outages"],answer:1,explanation:"Air-gapped networks (used for industrial control systems, classified government networks, or nuclear facility controls) eliminate remote network-based attack vectors entirely — but they're not immune to all threats, as demonstrated by Stuxnet, which crossed the air gap via infected USB drives, showing that physical/removable media controls remain critical even in air-gapped environments.",optionExplanations:["Air-gapping is about physical isolation/disconnection, the opposite of wireless connectivity.","Air gaps provide strong protection against remote network attacks by physically eliminating any network connection path, though they require strict physical and removable media controls to remain effective.","This is a network security architecture concept, not a physical cooling/spacing consideration.","Air-gapped networks are typically dedicated, isolated production networks for highly sensitive operations, not backup/failover networks."]},
  {id:818,domain:T,question:"What is an insider threat?",options:["Any threat originating from a foreign country","A security risk posed by individuals within an organization (employees, contractors, business partners) who have authorized access and may intentionally or unintentionally cause harm to the organization's security","A vulnerability found only in internal-use software","A threat that only affects internal company communications"],answer:1,explanation:"Insider threats can be malicious (a disgruntled employee stealing data before leaving), negligent (an employee falling for phishing or misconfiguring a cloud bucket), or compromised (an external attacker using stolen insider credentials) — insider threats are particularly dangerous because the individual already has legitimate, trusted access, bypassing many perimeter-focused defenses.",optionExplanations:["Insider threats specifically originate from within the organization, regardless of nationality — the defining factor is authorized internal access.","Insider threats are uniquely challenging because they originate from trusted, authorized individuals, requiring different detection approaches (behavioral analytics, UEBA) than external attacker-focused perimeter defenses.","This isn't specifically about software vulnerabilities; it's about risk from people with legitimate organizational access.","Insider threats can affect any organizational asset (data, systems, physical security), not just internal communications specifically."]},
  {id:819,domain:O,question:"What is the purpose of a disaster recovery (DR) test?",options:["A test conducted only after an actual disaster occurs","A planned, periodic exercise validating that an organization's disaster recovery plan and procedures actually work as documented, identifying gaps before a real disaster strikes","A test of employees' physical disaster preparedness knowledge only","A one-time test performed only when the DR plan is first written"],answer:1,explanation:"DR tests range from tabletop walkthroughs to full failover tests (actually cutting over to a DR site) — regularly scheduled testing (annually at minimum, often more frequently for critical systems) catches issues like outdated runbooks, missing dependencies, or failed backups before they're discovered during an actual crisis when the stakes are highest.",optionExplanations:["Testing the plan is meant to happen proactively, before a disaster, specifically to ensure readiness when one does occur.","Regular DR testing validates that documented procedures, technical failover mechanisms, and team readiness actually function correctly, surfacing gaps in a controlled setting rather than during a real, high-stakes crisis.","While awareness is part of it, DR tests primarily validate technical recovery capabilities and procedures, not solely employee general knowledge.","DR plans and the environment they protect change over time, requiring ongoing periodic testing to remain valid and effective."]},
  {id:820,domain:T,question:"What is a side-channel attack?",options:["An attack launched from a side/secondary network connection","An attack that exploits information gained from the physical implementation of a system (timing, power consumption, electromagnetic emissions, or sound) rather than exploiting weaknesses in the algorithm itself","An attack that targets only side menus in web applications","A backup attack method used if the primary attack fails"],answer:1,explanation:"Timing attacks measure how long cryptographic operations take to infer information about secret keys; power analysis attacks measure a smart card's power consumption during encryption to extract key bits; Spectre/Meltdown exploited CPU speculative execution timing — side-channel attacks bypass the mathematical strength of an algorithm entirely by exploiting its physical implementation.",optionExplanations:["This isn't about network topology/connection paths; it's about exploiting unintended physical information leakage.","Side-channel attacks are notable because they can defeat cryptographically sound algorithms by exploiting implementation-specific physical leakage (timing, power, EM emissions) rather than any mathematical weakness in the algorithm itself.","This isn't about UI elements; it's a hardware/implementation-level attack against the physical execution of cryptographic or computational processes.","This is a distinct, sophisticated attack category exploiting physical implementation details, not a fallback technique."]},
  {id:821,domain:G,question:"What is the purpose of a data classification policy?",options:["A policy that organizes data alphabetically for easier searching","A framework categorizing organizational data based on its sensitivity level (e.g., Public, Internal, Confidential, Restricted), determining the appropriate handling, storage, and protection requirements for each category","A policy that determines which file formats are allowed","A policy restricting data to a single physical location"],answer:1,explanation:"Data classification (often required by frameworks like FedRAMP, HIPAA) ensures that highly sensitive data (PII, financial records) receives stronger protections — encryption, restricted access, audit logging — while public data requires minimal controls, allowing organizations to allocate security resources proportionally to actual risk rather than applying uniform (and often inefficient) protection to all data.",optionExplanations:["Classification is based on sensitivity/risk level, not alphabetical or naming organization.","Data classification enables risk-appropriate, proportional security controls — without it, organizations either over-protect low-value data (wasting resources) or under-protect sensitive data (creating risk).","File format restrictions are a separate technical control, distinct from sensitivity-based classification.","Classification concerns handling requirements based on sensitivity, not physical data location/residency, though classification may inform location requirements."]},
  {id:822,domain:O,question:"What is the purpose of a security operations center (SOC) shift handoff process?",options:["A process for changing SOC physical furniture","A formal procedure ensuring continuity of awareness and ongoing investigations between outgoing and incoming SOC analyst shifts, preventing dropped incidents or lost context during shift changes","A process for rotating which analysts get which parking spots","A one-time process performed only during SOC opening"],answer:1,explanation:"Effective handoffs include a summary of ongoing investigations, unresolved alerts, any planned maintenance windows, and known issues — without proper handoff, an incident detected late in one shift might lose momentum or context when picked up (or missed) by the next shift, delaying response.",optionExplanations:["This isn't about physical workspace logistics; it's about operational continuity of security monitoring/investigation.","Continuous 24/7 SOC operations depend on smooth handoffs to maintain situational awareness and prevent incidents from falling through the cracks between shift changes.","Parking arrangements are unrelated to security operational continuity.","Handoffs occur at every shift change as an ongoing operational practice, not a one-time event."]},
  {id:823,domain:T,question:"What is a rootkit?",options:["A toolkit used by network administrators for routine maintenance","Malicious software designed to gain and maintain privileged (root/administrator) access to a system while actively hiding its presence from the operating system, security tools, and users","A starter kit for growing computer hardware components","A legitimate software installation package"],answer:1,explanation:"Kernel-level rootkits modify core OS components to intercept and falsify system calls, hiding malicious files, processes, and network connections from normal detection tools — because they operate at such a privileged level, rootkits are notoriously difficult to detect and often require specialized tools or a full OS reinstall to fully remove.",optionExplanations:["This describes legitimate admin tools, the opposite of malicious rootkit software.","Rootkits are distinguished by their stealth and persistence mechanisms — operating at a privileged level that lets them actively conceal their own presence from standard detection methods, unlike typical malware that just executes malicious payloads.","This is wordplay; rootkits have nothing to do with physical hardware kits.","Rootkits are malicious by definition, designed to maintain covert unauthorized access, unlike legitimate software installations."]},
  {id:824,domain:A,question:"What is the function of an HSM (Hardware Security Module) in an organization's cryptographic infrastructure?",options:["A module that physically secures server room doors","A dedicated, tamper-resistant physical device that securely generates, stores, and manages cryptographic keys and performs cryptographic operations, keeping private keys from ever being exposed to the host system's memory","A backup storage device for non-sensitive files","A module that monitors employee badge access"],answer:1,explanation:"HSMs are used for high-value key management scenarios like Certificate Authority root key protection, payment processing (PCI HSMs), and code signing — they're designed with tamper-evident/tamper-responsive mechanisms (some self-destruct keys if physical tampering is detected) and perform cryptographic operations internally so the private key material never leaves the hardware boundary.",optionExplanations:["This is a cryptographic device, not a physical building access control mechanism.","HSMs provide the highest level of key protection by ensuring private keys never exist in extractable form outside the tamper-resistant hardware, critical for high-value cryptographic operations like root CA key protection.","HSMs specifically protect sensitive cryptographic key material, not general-purpose file backup.","Badge access monitoring is physical security, unrelated to HSM's cryptographic key management function."]},
  {id:825,domain:O,question:"What is the purpose of the 'containment' phase in the incident response lifecycle?",options:["Permanently deleting all evidence related to the incident","Taking actions to limit the scope and spread of an ongoing security incident, preventing further damage while preserving evidence for later analysis, often before full eradication occurs","Containing the incident response team in a single room","Writing the final incident report"],answer:1,explanation:"Containment strategies range from short-term (isolating an infected host from the network while preserving its memory state for forensics) to long-term (rebuilding affected systems from clean images) — the goal is to stop the bleeding without destroying evidence needed to fully understand and remediate the root cause.",optionExplanations:["Containment specifically requires preserving evidence, not destroying it — evidence destruction would actually hinder eradication and lessons-learned efforts.","Containment is a critical NIST IR lifecycle phase that balances stopping ongoing damage with preserving forensic evidence, distinct from eradication (removing the threat) and recovery (restoring normal operations).","This isn't about physical team logistics; it's about limiting the technical scope of an incident.","Report writing occurs in the post-incident activity phase, distinct from the active containment phase during incident response."]},
  {id:826,domain:T,question:"What is a botnet?",options:["A legitimate network of customer service chatbots","A network of compromised, internet-connected devices (bots) infected with malware and controlled remotely by an attacker (botmaster), often used for DDoS attacks, spam distribution, or cryptocurrency mining","A network exclusively for robot manufacturing","A backup network maintained by ISPs"],answer:1,explanation:"The Mirai botnet famously compromised hundreds of thousands of IoT devices (cameras, routers) with weak default credentials, using their combined bandwidth to launch some of the largest DDoS attacks recorded — botnets derive their power from scale, allowing attackers to harness massive distributed computing/bandwidth resources without owning any of the infrastructure themselves.",optionExplanations:["This describes legitimate customer service automation, unrelated to malicious compromised device networks.","Botnets provide attackers with massive distributed capability (for DDoS, spam, cryptomining, or further malware distribution) by aggregating control over thousands or millions of compromised devices, often without owners' knowledge.","This is wordplay; botnets refer to compromised computing devices, not robot manufacturing infrastructure.","Botnets are malicious infrastructure controlled by attackers, not legitimate ISP backup systems."]},
  {id:827,domain:P,question:"What is the purpose of a records of processing activities (RoPA) document under GDPR?",options:["A document recording employee attendance","A documented inventory of an organization's personal data processing activities, including what data is collected, why, how it's used, who has access, and retention periods, required for GDPR Article 30 compliance","A list of all IT equipment purchases","A record of physical office visitor logs"],answer:1,explanation:"RoPA documentation provides accountability and transparency, helping organizations (and regulators during audits) understand the full scope of personal data processing across the enterprise — it's foundational for demonstrating GDPR compliance and is often a prerequisite for conducting effective privacy impact assessments.",optionExplanations:["This isn't about employee attendance tracking; it documents personal data processing activities specifically.","RoPA is a core GDPR accountability requirement, providing the documented foundation organizations need to demonstrate compliance and respond to data subject requests or regulatory inquiries.","Equipment procurement records are unrelated to personal data processing documentation requirements.","Visitor logs are a physical security record, distinct from the data processing activity documentation required under GDPR Article 30."]},
  {id:828,domain:T,question:"What is a zero-day exploit?",options:["An exploit that takes zero days to develop","An exploit that targets a previously unknown vulnerability for which no patch or fix yet exists, giving defenders zero days of advance warning to prepare or remediate","An exploit only usable on the day it's released","A vulnerability that has existed for zero days since the system was deployed"],answer:1,explanation:"Zero-day vulnerabilities are especially dangerous because traditional signature-based defenses and patches don't yet exist — they're often discovered and weaponized by sophisticated threat actors (nation-states, well-resourced criminal groups) and sold on underground markets for substantial sums before vendors become aware and can issue patches.",optionExplanations:["Zero-day exploits can take significant time and skill to develop; 'zero-day' refers to the defenders having zero days of advance warning, not the development timeline.","The term refers to the vulnerability being unknown to the vendor/defenders ('zero days' to prepare a fix), making zero-days particularly valuable to attackers since no patch or signature-based detection yet exists.","Zero-day exploits often remain usable for an extended period after initial use, until the vulnerability is discovered and patched.","'Zero-day' describes the lack of advance defender knowledge/patch availability, not the system's deployment age."]},
  {id:829,domain:A,question:"What is the purpose of secure boot in modern computing devices?",options:["Booting the system faster than normal","A security feature that verifies each component loaded during the boot process (firmware, bootloader, OS kernel) is cryptographically signed and trusted, preventing execution of unauthorized or malicious code before the OS fully loads","Booting the system into a secure, isolated guest mode","Encrypting the boot password only"],answer:1,explanation:"Secure boot establishes a chain of trust starting from the hardware root of trust (often anchored in the TPM or UEFI firmware) through each subsequent boot stage — if malware (like a bootkit) attempts to tamper with any component in this chain, the signature verification fails and the system refuses to boot that compromised component, preventing pre-OS-level persistence.",optionExplanations:["Secure boot is about integrity verification, not boot speed optimization (it actually adds minor verification overhead).","Secure boot specifically defends against low-level persistence threats like bootkits and rootkits that try to compromise the system before the OS and its security tools even load, by enforcing cryptographic verification at each boot stage.","This isn't about creating an isolated guest session; it's about verifying boot component integrity for the primary OS.","Secure boot validates code signatures throughout the boot chain, not specifically password encryption."]},
  {id:830,domain:O,question:"What is the purpose of a vulnerability management program's risk-based prioritization?",options:["Patching vulnerabilities in alphabetical order by CVE ID","Prioritizing remediation efforts based on factors like CVSS severity score, exploit availability, asset criticality, and exposure, rather than treating all vulnerabilities as equally urgent","Patching only vulnerabilities reported by external researchers","Ignoring vulnerabilities with low CVSS scores entirely"],answer:1,explanation:"A critical CVSS 9.8 vulnerability on an internal, isolated test server with no internet exposure may actually be lower priority than a CVSS 7.5 vulnerability on an internet-facing production server with a known public exploit — risk-based prioritization (using frameworks like EPSS alongside CVSS) ensures limited patching resources address the vulnerabilities posing the greatest actual organizational risk first.",optionExplanations:["CVE ID ordering has no relationship to actual risk or urgency; it's simply a sequential identifier.","Risk-based prioritization recognizes that not all vulnerabilities pose equal real-world risk — context like exploitability, asset value, and exposure must factor in alongside raw severity scores to allocate limited remediation resources effectively.","Vulnerability sourcing (internal scan vs external researcher) doesn't determine remediation priority; actual risk factors do.","Low CVSS vulnerabilities can still pose meaningful risk in certain contexts (e.g., when chained with other vulnerabilities) and shouldn't be entirely ignored, just appropriately deprioritized."]},
  {id:831,domain:T,question:"What is a malicious USB drop attack?",options:["An attack that drops USB prices in a store","A social engineering technique where attackers leave infected USB drives in locations where targets are likely to find and plug them in out of curiosity, triggering malware execution","An attack that physically damages USB ports","A technique for safely disposing of old USB drives"],answer:1,explanation:"Attackers might leave USB drives labeled 'Salary Information' or 'Confidential' in a company parking lot — curiosity drives employees to plug them into work computers, where autorun malware or a malicious HID (Human Interface Device) emulation script executes automatically, demonstrating how physical and psychological attack vectors combine.",optionExplanations:["This is wordplay; the attack involves dropping (leaving) physical devices, not pricing.","USB drop attacks exploit human curiosity as the attack vector, bypassing network-based defenses entirely since the malware is delivered via physical media rather than over the network.","This is a social engineering/malware delivery technique, not physical port damage.","This describes a malicious attack technique, not a legitimate, secure disposal practice."]},
  {id:832,domain:A,question:"What is the purpose of a Web Application Firewall (WAF) in protecting web applications?",options:["A physical firewall device placed near web servers in the data center","A security control that filters, monitors, and blocks malicious HTTP/HTTPS traffic to and from a web application, protecting against attacks like SQL injection, XSS, and other OWASP Top 10 vulnerabilities","A firewall that only blocks traffic from specific countries","A backup system for web application code"],answer:1,explanation:"WAFs (Cloudflare, AWS WAF, ModSecurity) operate at Layer 7, inspecting actual HTTP request content against rule sets (signature-based or anomaly-based) to block malicious payloads before they reach the application — providing a critical compensating control for vulnerabilities that haven't yet been patched in the application code itself.",optionExplanations:["WAFs operate at the application layer inspecting HTTP traffic content, distinct from a traditional network-layer physical firewall appliance.","WAFs specifically target web application-layer attacks by inspecting HTTP request/response content, providing protection against the OWASP Top 10 vulnerability classes that traditional network firewalls can't detect.","Geo-blocking can be one feature of some WAFs, but the core function is content-based malicious traffic filtering, not solely geographic restriction.","WAFs filter live traffic; they don't provide code backup/version control functionality."]},
  {id:833,domain:O,question:"What is the purpose of an incident response retainer agreement with a third-party firm?",options:["A retainer that guarantees a firm will never report incidents to authorities","A pre-arranged contract with an external incident response/forensics firm ensuring rapid access to specialized expertise and resources during a major incident, without negotiating terms during the high-pressure crisis itself","A retainer fee paid to law enforcement for protection","An agreement that replaces the need for an internal IR team entirely"],answer:1,explanation:"Organizations without 24/7 in-house deep forensic capability often establish retainers with firms like Mandiant or CrowdStrike Services beforehand — this guarantees rapid response time (often contracted SLAs of hours, not days) and avoids the costly delay of vetting and negotiating contracts while actively under attack.",optionExplanations:["Legal/regulatory reporting obligations exist independently of any retainer agreement and firms wouldn't legally agree to violate them.","Pre-negotiated retainers eliminate the time-consuming vendor selection and contract negotiation process during an active crisis, when speed of response significantly impacts incident containment and damage.","This isn't a payment to law enforcement; it's a contract with a private incident response/forensics service provider.","Retainers typically augment internal capabilities for surge capacity or specialized expertise, rather than replacing an organization's own internal incident response function entirely."]},
  {id:834,domain:T,question:"What is a malvertising attack?",options:["An attack on advertising agency physical offices","Malicious advertising — using legitimate online advertising networks to distribute malware or redirect users to malicious sites, often without requiring any user interaction beyond viewing the ad","A type of spam email about products","A technique for creating fake online reviews"],answer:1,explanation:"Attackers purchase ad space through legitimate ad networks (which often have automated, less-vetted approval processes) and embed malicious code or redirects in the ad creative — drive-by-download malvertising can compromise visitors of even well-known, reputable websites without any click, just by loading a page containing the malicious ad.",optionExplanations:["This is a digital attack vector through online ad networks, not a physical office attack.","Malvertising is particularly insidious because it can compromise users on completely legitimate, trusted websites through the ad supply chain, sometimes requiring no user interaction at all (drive-by downloads).","This isn't email spam; it's malicious content distributed through legitimate online advertising networks/exchanges.","Fake reviews are a different deceptive marketing practice, unrelated to malware distribution via ad networks."]},
  {id:835,domain:G,question:"What is the concept of 'security through obscurity' and why is it generally considered insufficient as a primary defense?",options:["Relying solely on hiding system details or implementation rather than strong, well-vetted security controls — generally insufficient because once the obscured details are discovered, the system is left with no real protection", "A formal cryptographic algorithm design principle","A government classification system","A method requiring all security configurations be kept hidden from auditors"],answer:0,explanation:"Examples include running services on non-standard ports hoping attackers won't find them, or using a custom, unvetted encryption algorithm instead of a proven one — while obscurity can be one layer in defense-in-depth, relying on it alone fails catastrophically once the secret is discovered (e.g., through scanning, reverse engineering, or insider leak), since there's no underlying robust control.",optionExplanations:["This accurately describes the concept and its key weakness — Kerckhoffs's principle states a system should be secure even if everything about it except the key is public knowledge, which security through obscurity violates.","This describes the opposite; legitimate cryptographic design follows open, peer-reviewed standards (Kerckhoffs's principle) rather than relying on secrecy of the algorithm itself.","This isn't a formal government classification framework; it's a general security design anti-pattern/criticism.","Hiding configurations from legitimate auditors would actually undermine security governance and accountability, not represent the concept being described."]},
  {id:836,domain:O,question:"What is the purpose of network flow data (NetFlow/sFlow) analysis in security monitoring?",options:["Analyzing only the physical flow of water cooling systems","Collecting and analyzing metadata about network traffic flows (source/destination IPs, ports, protocols, byte counts) without capturing full packet content, useful for detecting anomalous traffic patterns and supporting incident investigation","A tool for managing employee workflow approvals","A technique for measuring internet service provider billing"],answer:1,explanation:"NetFlow data is much smaller than full packet captures, making it practical to retain for long periods — security teams can use it to identify unusual data exfiltration volumes, detect communication with known malicious IPs, or trace lateral movement patterns during an investigation, even without the full packet content that would be needed for deep content inspection.",optionExplanations:["This is network traffic metadata analysis, unrelated to physical cooling infrastructure.","NetFlow/sFlow provides a scalable way to monitor traffic patterns and detect anomalies (volume spikes, unusual destinations) across an entire network without the storage overhead of full packet capture, making it valuable for both real-time monitoring and historical investigation.","This isn't about business process workflow; it's network traffic metadata used for security visibility.","While ISPs may use flow data for billing in some contexts, the security application is about traffic pattern analysis and anomaly detection, not billing."]},
  {id:837,domain:T,question:"What is a man-in-the-middle (MITM) attack at a fundamental level?",options:["An attack requiring the attacker to be a literal middle manager","An attack where an adversary secretly intercepts and potentially alters communications between two parties who believe they are communicating directly with each other","A negotiation tactic in business deals","An attack targeting only middleware software components"],answer:1,explanation:"MITM can occur at many layers — ARP poisoning (Layer 2), rogue WiFi APs, BGP hijacking, or compromised/malicious TLS certificates — the unifying theme is that the attacker positions themselves transparently in the communication path, often able to eavesdrop, modify data in transit, or impersonate one or both parties without either realizing the interception is occurring.",optionExplanations:["This is wordplay; MITM has nothing to do with organizational hierarchy/management positions.","MITM is a broad attack category unified by the attacker's positioning in the communication path, applicable across many different protocols and layers — the core threat is the betrayal of an assumed direct, private communication channel.","This isn't a business negotiation strategy; it's a technical security attack pattern.","While middleware can be a target in some scenarios, MITM as a concept applies broadly to any intercepted communication channel, not specifically middleware software."]},
  {id:838,domain:A,question:"What is the purpose of implementing rate limiting on an API or login endpoint?",options:["Rate limiting determines how much customers are billed","Restricting the number of requests a client can make within a specified time period, protecting against brute force attacks, credential stuffing, denial of service, and API abuse","Limiting only the speed of file downloads","A feature that has no security purpose, only performance benefits"],answer:1,explanation:"A login endpoint with rate limiting (e.g., max 5 attempts per minute per IP) significantly slows down brute force and credential stuffing attacks, making them impractical at scale, while API rate limiting prevents a single client from monopolizing resources or scraping data en masse — proper rate limiting also helps protect against application-layer DoS attacks.",optionExplanations:["Billing rate is a separate business/commercial concept, distinct from request throttling for security purposes.","Rate limiting is a critical control against several attack categories — by capping request frequency, it makes automated, high-volume attacks (brute force, credential stuffing, scraping) impractical or significantly slower.","Rate limiting applies broadly to any request type, not exclusively file downloads.","While performance benefits exist, rate limiting has clear security value specifically as an anti-automation and anti-abuse control."]},
  {id:839,domain:O,question:"What is the purpose of a security control self-assessment versus an independent audit?",options:["Self-assessments are always more reliable than independent audits","A self-assessment is conducted internally by the organization to evaluate its own control effectiveness, often as ongoing governance, while an independent audit is conducted by an external, objective party to validate compliance and control effectiveness with greater assurance", "Self-assessments are required by law while audits are optional","There is no meaningful difference between the two"],answer:1,explanation:"Self-assessments are valuable for continuous internal monitoring and catching issues early at lower cost, but they can suffer from bias or blind spots since the assessor may be evaluating their own work — independent audits (SOC 2, ISO 27001 certification audits) provide external validation with greater credibility for customers, regulators, and business partners specifically because of their objectivity.",optionExplanations:["Independent audits generally provide higher assurance due to their objectivity, though self-assessments serve a valuable, more frequent internal monitoring purpose.","This distinction reflects the tradeoff between frequency/cost (self-assessment) and assurance/credibility (independent audit) — mature security programs typically use both as complementary approaches.","Requirements vary by industry and regulation; neither is universally mandated, though certain compliance frameworks may require independent audits specifically.","These serve distinct, complementary purposes with different levels of assurance, objectivity, and typical use cases within a governance program."]},
  {id:840,domain:T,question:"What is a heap spray attack technique?",options:["A technique for cleaning up unused memory","An exploitation technique that fills a large portion of a program's heap memory with attacker-controlled shellcode/NOP sleds, increasing the probability that a memory corruption vulnerability will redirect execution into the attacker's injected code","A technique for compressing data in memory","A network attack that floods routers with spray-pattern packets"],answer:1,explanation:"Because exact memory addresses are often unpredictable (especially with ASLR), heap spraying increases the attacker's odds of success by saturating large swaths of memory with shellcode preceded by long NOP sled sequences — if the corrupted pointer lands anywhere within the sprayed region, execution likely slides into the malicious payload, commonly used in browser/JavaScript engine exploits.",optionExplanations:["This is an offensive exploitation technique, not a memory management/garbage collection process.","Heap spraying is a probabilistic exploitation technique that compensates for memory layout unpredictability by saturating memory with attacker-controlled content, commonly paired with browser-based memory corruption vulnerabilities.","This isn't about data compression; it's about filling memory with malicious payload for exploitation purposes.","This is a memory exploitation technique, unrelated to network packet flooding attacks against routers."]},
  {id:841,domain:A,question:"What is the purpose of a sandbox environment in malware analysis?",options:["A children's recreational area at a tech company","An isolated, controlled environment where suspicious files or code can be safely executed and observed to analyze their behavior without risking damage to production systems","A sandbox used only for testing UI designs","A backup environment used during disaster recovery"],answer:1,explanation:"Dynamic malware analysis sandboxes (Cuckoo Sandbox, Joe Sandbox, ANY.RUN) execute suspicious files in a monitored virtual environment, recording file system changes, network connections, and process behavior — this allows analysts to understand malware capabilities and IOCs (indicators of compromise) without risking infection of real systems, though sophisticated malware may include sandbox-evasion techniques to detect and avoid analysis.",optionExplanations:["This is a technical security analysis tool, not a literal recreational sandbox.","Sandboxing provides safe behavioral analysis of unknown/suspicious code, critical for understanding new malware threats and extracting actionable threat intelligence without risking production system compromise.","UI/UX testing environments are a different concept from security analysis sandboxes.","DR environments serve business continuity, a different purpose from isolated malware behavioral analysis."]},
  {id:842,domain:T,question:"What is a DNS amplification attack?",options:["An attack that improves DNS resolution speed for legitimate users","A DDoS technique exploiting DNS servers configured to respond to small spoofed queries with much larger responses, directing the amplified traffic at a victim whose IP was spoofed as the query source","An attack that physically amplifies network signal strength","A method for legitimately scaling DNS infrastructure"],answer:1,explanation:"Attackers send small DNS queries (e.g., 60 bytes) with a spoofed source IP set to the victim's address, to open DNS resolvers that return large responses (e.g., 3000+ bytes) — this amplification factor (potentially 50x or more) combined with reflection (the response goes to the spoofed victim, not the attacker) makes DNS amplification a powerful and popular DDoS technique.",optionExplanations:["This attack degrades, not improves, performance for the victim being flooded with amplified traffic.","DNS amplification combines two techniques — reflection (spoofed source IP) and amplification (small request, large response) — to achieve devastating DDoS impact while obscuring the true attacker's identity and location.","This is a network-layer traffic volume attack technique, not related to physical RF signal amplification.","This describes malicious DDoS traffic generation, not legitimate DNS infrastructure scaling/capacity planning."]},
  {id:843,domain:O,question:"What is the purpose of conducting red team versus blue team versus purple team exercises?",options:["Red, blue, and purple refer to different colored uniforms with no functional difference","Red team simulates real-world attackers to test defenses, blue team defends and detects, and purple team facilitates collaboration and knowledge sharing between red and blue to maximize the learning and improvement from the exercise","These terms refer to different shifts of the same SOC team performing identical tasks","Only the blue team's findings are considered valid in security assessments"],answer:1,explanation:"Pure red team exercises test detection/response capability adversarially (sometimes without blue team's prior knowledge), while purple teaming intentionally breaks down the wall between offense and defense — red and blue work together in real time, with red team explaining techniques as they execute them so blue team can immediately validate and tune their detection capability, accelerating the overall security improvement cycle.",optionExplanations:["Each team has fundamentally different objectives, skill sets, and methodologies, not just cosmetic differences.","This collaborative model (purple teaming) has become increasingly popular because it accelerates defensive improvement by providing immediate feedback, rather than only finding gaps after an adversarial exercise concludes.","These represent functionally distinct roles and methodologies (offense vs defense vs collaborative), not simply shift rotations of identical work.","Both red team findings (gaps in defense) and blue team findings (what was detected/missed) provide valuable, complementary insights into overall security posture."]},
  {id:844,domain:T,question:"What is an attack surface, and why is reducing it important?",options:["The physical surface area of a server rack","The sum of all points (entry points, vulnerabilities, exposed services, code paths) where an unauthorized user could potentially attempt to enter or extract data from a system, with a smaller attack surface generally meaning fewer opportunities for exploitation","A surface used only for malware delivery via USB","A term referring only to network perimeter firewalls"],answer:1,explanation:"Attack surface reduction techniques include disabling unused services, removing unnecessary software, closing unused ports, and minimizing exposed APIs — every additional feature, open port, or running service represents another potential vector an attacker could exploit, so the security principle is to minimize what's exposed to only what's functionally necessary.",optionExplanations:["This is a conceptual/logical security measure, not a literal physical hardware dimension.","Attack surface encompasses all potential entry/exit points across software, network, and even physical/human vectors — reducing it (via least functionality, hardening) directly reduces the number of ways an attacker could potentially compromise a system.","Attack surface is a broad concept covering all exposure points, not limited to any single delivery mechanism like USB.","Attack surface extends well beyond network perimeter firewalls to include application code, APIs, exposed services, and even human/social engineering vectors."]},
  {id:845,domain:G,question:"What is the purpose of a risk register?",options:["A register listing all employees with security clearances","A documented, centralized inventory of identified organizational risks, including their likelihood, potential impact, current mitigation status, and assigned risk owner, used to track and manage risk over time","A list of approved software vendors","A log of all network login attempts"],answer:1,explanation:"Risk registers provide visibility for risk management decision-making — leadership can review the register to see, for example, that an unpatched legacy system represents a 'High' likelihood/'High' impact risk currently being mitigated through network segmentation while a permanent fix is planned, supporting informed risk acceptance, transfer, mitigation, or avoidance decisions.",optionExplanations:["This is a risk management tracking document, not a personnel security clearance list.","The risk register is a foundational risk management artifact, providing ongoing visibility into the organization's risk landscape and enabling prioritized, informed decision-making about where to allocate mitigation resources.","Vendor approval lists are a separate procurement/vendor management artifact, distinct from organizational risk tracking.","Login attempt logs are operational security monitoring data, a different category from strategic risk management documentation."]},
  {id:846,domain:O,question:"What is the purpose of establishing escalation procedures within an incident response plan?",options:["Procedures for escalating employee salaries","Predefined criteria and processes for promptly notifying appropriate personnel (management, legal, executives) based on incident severity, ensuring the right people are involved at the right time during a security incident","A procedure for promoting analysts to senior positions","A process used exclusively for IT help desk tickets"],answer:1,explanation:"Escalation procedures specify, for example, that any incident involving suspected data breach of customer PII must immediately notify legal counsel and the CISO within 1 hour, while a routine malware detection on an isolated workstation follows standard analyst-level handling — clear escalation criteria prevent both under-escalation (executives unaware of a major breach) and over-escalation (executives drowning in minor alert noise).",optionExplanations:["This is unrelated to compensation; escalation procedures govern incident notification chains.","Well-defined escalation criteria ensure appropriate stakeholders (legal, executive, regulatory) are engaged at the right severity threshold, balancing timely awareness against alert fatigue from over-escalating minor incidents.","Career advancement is an HR process, distinct from incident severity-based notification procedures.","While help desk tickets may have similar concepts, formal incident response escalation procedures specifically address security incident severity and stakeholder notification, a broader scope than general IT support."]},
  {id:847,domain:T,question:"What is a pretexting social engineering attack?",options:["An attack that occurs before any actual text message is sent","A social engineering technique where an attacker creates a fabricated scenario or false identity (pretext) to manipulate a victim into divulging information or performing an action they otherwise wouldn't", "A method for testing software before release","An attack targeting SMS text messaging systems specifically"],answer:1,explanation:"Example: an attacker calls the help desk claiming to be a traveling executive who's locked out and urgently needs a password reset, fabricating enough plausible detail (correct employee ID, knowledge of org structure) to convince the help desk technician to bypass normal verification procedures — pretexting relies on a convincing, prepared backstory rather than urgency or fear alone.",optionExplanations:["This is wordplay; pretexting refers to a fabricated 'pretext' scenario/story, unrelated to SMS text messaging timing.","Pretexting's effectiveness comes from the attacker's prepared, plausible false narrative that establishes false trust or authority, distinguishing it from simpler social engineering relying purely on urgency or generic deception.","This isn't software QA testing; it's a social engineering manipulation technique targeting humans.","Pretexting can occur over phone, email, in-person, or any communication channel — it's not specific to SMS technology."]},
  {id:848,domain:A,question:"What is the purpose of implementing TLS mutual authentication (mTLS)?",options:["A protocol requiring both parties to mutually agree on a price","A configuration where both the client and server authenticate each other using digital certificates during the TLS handshake, rather than only the server presenting a certificate as in standard TLS, providing stronger bidirectional trust","A backup TLS configuration used only during outages","A protocol that doubles encryption strength automatically"],answer:1,explanation:"mTLS is commonly used for service-to-service authentication in zero trust architectures and API security (microservices communicating within a service mesh) — since both parties present and validate certificates, it provides strong mutual identity assurance, ensuring a malicious or unauthorized client can't connect even if it knows the correct endpoint URL.",optionExplanations:["This isn't about pricing negotiation; it's about cryptographic bidirectional identity verification.","mTLS extends standard one-way TLS server authentication to also authenticate the client, providing stronger assurance critical for zero-trust environments where verifying both endpoints' identities is essential.","mTLS is a standard, ongoing configuration for appropriate use cases, not solely a failover/outage mechanism.","mTLS doesn't double encryption strength; it adds an additional authentication direction (client authentication) to the existing TLS handshake."]},
  {id:849,domain:O,question:"What is the purpose of conducting a root cause analysis (RCA) after a security incident?",options:["Identifying which employee to discipline for the incident","A systematic process for identifying the fundamental, underlying cause of an incident (not just its immediate symptoms), enabling organizations to implement corrective actions that prevent recurrence", "A financial analysis of incident response costs","A process performed only for incidents involving physical security"],answer:1,explanation:"RCA techniques like the '5 Whys' help teams move past surface-level findings (e.g., 'malware got in through a phishing email') to deeper systemic issues (e.g., 'why did the email bypass filtering? Why wasn't MFA enforced? Why was the employee's training overdue?') — addressing only symptoms without RCA often leads to repeat incidents from the same underlying gaps.",optionExplanations:["RCA in security contexts focuses on systemic/technical causes and process gaps, not assigning individual blame, which discourages honest incident reporting.","RCA distinguishes itself from simple incident documentation by digging into systemic causes, ensuring remediation addresses the actual root issue rather than just the visible symptom, preventing recurrence of similar incidents.","While cost may be tracked separately, RCA's primary focus is causal/technical analysis, not financial accounting.","RCA applies to security incidents broadly across all domains (technical, physical, procedural), not exclusively physical security incidents."]},
  {id:850,domain:T,question:"What is a watering hole versus drive-by download attack — what's the key relationship?",options:["They are completely unrelated and never occur together","A watering hole attack often uses a drive-by download as its delivery mechanism — once a target visits the compromised legitimate site, malicious code automatically attempts to exploit browser vulnerabilities and install malware without further user interaction","Drive-by downloads only occur through email attachments","Watering hole attacks always require the victim to manually download and run a file"],answer:1,explanation:"In a typical watering hole attack chain, attackers first compromise a legitimate, trusted website frequented by their target group, then embed exploit code that performs a drive-by download — automatically attempting to exploit unpatched browser or plugin vulnerabilities to silently install malware the moment a vulnerable visitor loads the page, with no click or download action required from the victim.",optionExplanations:["These techniques are frequently combined, with drive-by download serving as the actual malware delivery mechanism within a watering hole campaign.","This combination is a classic and dangerous pairing — the watering hole provides the trusted delivery vector (a site victims already visit) while drive-by download provides the automatic, no-interaction-required exploitation and infection mechanism.","Drive-by downloads occur through compromised or malicious web pages, not specifically email attachments (which would be a different delivery vector).","The defining characteristic of a drive-by download is that it requires no explicit manual download/run action — infection occurs automatically just from visiting the page."]},
  {id:851,domain:G,question:"What is the purpose of conducting threat modeling during the software design phase?",options:["Modeling software performance under heavy load only","A structured process for identifying potential threats, vulnerabilities, and attack vectors to a system during design, allowing security controls to be built in proactively rather than added as an afterthought after deployment", "Creating 3D visual models of network topology","A modeling technique used only for marketing materials"],answer:1,explanation:"Frameworks like STRIDE (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) help development teams systematically consider 'what could go wrong' for each component during design — identifying and addressing security issues at the design phase is dramatically cheaper than discovering and fixing them after deployment or, worse, after an actual breach.",optionExplanations:["Threat modeling addresses security risks broadly, not specifically performance/load testing.","Threat modeling embodies 'shift-left' security principles, embedding security consideration into the design process when changes are cheapest and architectural decisions can still accommodate necessary controls.","This isn't about visual network diagramming; it's an analytical security risk identification process during design.","Threat modeling is a technical security engineering practice, unrelated to marketing content creation."]},
  {id:852,domain:O,question:"What is the purpose of a security exception/risk acceptance process?",options:["A process for permanently ignoring all security policies","A formal, documented process for evaluating, approving, and tracking instances where a system or process cannot fully comply with security policy, requiring risk owner sign-off and often compensating controls or a remediation timeline","A process used only to fire employees who violate policy","An automated process requiring no human review"],answer:1,explanation:"Example: a legacy application requiring an outdated, vulnerable protocol can't be immediately replaced due to business constraints — a documented exception with compensating controls (network isolation, enhanced monitoring) and an executive risk owner's sign-off ensures the risk is consciously accepted and tracked, rather than silently ignored or indefinitely deferred without accountability.",optionExplanations:["Exception processes formally document and track non-compliance with required justification and oversight, rather than allowing unchecked policy violations.","Formal exception processes maintain governance accountability — ensuring deviations from policy are deliberate, time-bound, and have an accountable risk owner, rather than becoming permanent unmanaged gaps.","This is a risk governance process, not a disciplinary/HR action against individuals.","Exception requests require human risk owner review and approval/sign-off, as automated approval would undermine the governance purpose of the process."]},
  {id:853,domain:T,question:"What is a Distributed Reflection Denial of Service (DRDoS) attack?",options:["A denial of service attack using only a single attacking machine","A DDoS technique where an attacker spoofs the victim's IP address when sending requests to legitimate third-party servers, causing those servers to send their responses to the victim, amplifying traffic while hiding the attacker's true source", "An attack that reflects sunlight to damage data center cooling systems","A legitimate load testing technique used by network administrators"],answer:1,explanation:"DRDoS combines reflection (using legitimate, innocent third-party servers as unwitting amplifiers) with spoofing (hiding the true attacker identity) — DNS amplification and NTP amplification attacks are specific examples of DRDoS that have been used to generate some of the largest DDoS attacks ever recorded, since the 'reflectors' are typically high-bandwidth, legitimate servers.",optionExplanations:["DRDoS is inherently distributed, leveraging many third-party reflector servers, not a single attacking source.","DRDoS's power comes from combining two techniques — using legitimate servers as unwitting traffic reflectors and IP spoofing to mask the true attacker — generating massive volumetric attacks while complicating attribution.","This is a network/protocol-based digital attack, unrelated to any physical/environmental attack vector.","DRDoS is an unauthorized, malicious attack technique, distinct from legitimate, authorized load testing performed with proper consent."]},
  {id:854,domain:A,question:"What is the purpose of implementing a bastion host (jump server)?",options:["A host that physically blocks unauthorized building entry","A hardened, tightly controlled and monitored server that serves as the single, controlled entry point for administrative access into a private/internal network segment, reducing the attack surface exposed for remote administration","A backup server used only during failover events","A host used exclusively for hosting public websites"],answer:1,explanation:"Instead of allowing direct SSH/RDP access to every internal server from the internet, administrators connect first to the bastion host (which is heavily hardened, monitored, and often requires MFA), then jump from there to internal systems — this consolidates administrative access through a single auditable, well-defended chokepoint rather than exposing many systems directly.",optionExplanations:["Bastion hosts are a network/logical security control, not a physical building security measure.","Bastion hosts centralize and harden the administrative access path, providing a single point for strong authentication, monitoring, and auditing rather than exposing numerous internal systems directly to external administrative connections.","Bastion hosts serve an ongoing operational security purpose for controlled access, distinct from disaster recovery failover systems.","Bastion hosts are specifically for controlled internal administrative access, the opposite of public-facing web hosting."]},
  {id:855,domain:O,question:"What is the purpose of automated patch management systems?",options:["Systems that automatically write new application code","Tools that automate the process of identifying, testing, deploying, and verifying security patches across an organization's systems, reducing the window of vulnerability exposure from manual, inconsistent patching processes","Systems used only for patching physical building infrastructure","A backup tool unrelated to security updates"],answer:1,explanation:"Automated patch management (WSUS, SCCM, Ivanti) can identify missing patches across thousands of endpoints, deploy them in scheduled maintenance windows, and report on patch compliance status — given that unpatched known vulnerabilities remain one of the most common breach causes, automation significantly reduces the time window during which systems remain exposed to known, exploitable flaws.",optionExplanations:["Patch management deploys vendor-released fixes, it doesn't generate new application code.","Automated patch management directly addresses one of the most persistent root causes of breaches — unpatched known vulnerabilities — by reducing the time and consistency gaps inherent in manual patching across large environments.","This is software/system patching, distinct from physical facility maintenance.","Patch management is specifically focused on deploying security and functionality updates, directly relevant to maintaining a secure posture."]},
  {id:856,domain:T,question:"What is a smishing attack?",options:["A phishing attack conducted via fax machines","Phishing conducted via SMS text messages, attempting to trick recipients into clicking malicious links or divulging sensitive information through deceptive text messages","An attack targeting smart home devices specifically","A legitimate SMS-based two-factor authentication system"],answer:1,explanation:"Smishing messages often impersonate banks, delivery services, or government agencies ('Your package couldn't be delivered, click here to reschedule') — SMS messages can be particularly effective since mobile users may have lower guard against text-based deception compared to email, and links are harder to inspect/hover-preview on mobile devices.",optionExplanations:["Smishing specifically refers to SMS (text message)-based phishing, not fax-based deception.","Smishing exploits the unique trust and lower scrutiny users often apply to SMS messages compared to email, combined with the difficulty of verifying links on mobile devices before tapping them.","While IoT/smart devices can be targeted by other attacks, 'smishing' specifically refers to SMS phishing, not a smart-device-specific attack category.","This describes a legitimate security feature (SMS-based 2FA), the opposite of the malicious smishing attack technique."]},
  {id:857,domain:P,question:"What is the purpose of a service organization control (SOC) 2 Type II report?",options:["A report verifying a company's annual revenue","An independent auditor's report verifying that an organization's controls related to security, availability, processing integrity, confidentiality, and/or privacy operated effectively over a specified period of time (not just at a single point in time)","A report verifying physical building safety code compliance","A marketing brochure describing a company's products"],answer:1,explanation:"SOC 2 Type II differs from Type I (which only verifies controls were suitably designed at a single point in time) by testing operating effectiveness over a period (typically 6-12 months) — this distinction matters because a control could be well-designed on paper but not consistently followed in practice, which Type II's extended observation period is specifically designed to catch.",optionExplanations:["SOC 2 is unrelated to financial revenue reporting; it specifically addresses security/trust service criteria.","Type II's extended testing period provides significantly stronger assurance than a point-in-time assessment, since it validates consistent, ongoing operational effectiveness rather than just design adequacy.","SOC 2 addresses information security and related trust principles, not building/fire safety code compliance.","SOC 2 reports are formal audit deliverables used for vendor due diligence and compliance, not promotional marketing materials."]},
  {id:858,domain:T,question:"What is an on-path attack (formerly known as man-in-the-middle)?",options:["An attack that requires physical presence on a delivery route", "An attack where the adversary positions themselves between two communicating parties to intercept, and potentially alter, the data being exchanged, without either party's knowledge", "A legitimate network path optimization technique","An attack targeting only postal mail systems"],answer:1,explanation:"CompTIA's updated terminology ('on-path attack') describes the same concept previously called 'man-in-the-middle' — emphasizing the attacker's network position relative to the communication path rather than gendered terminology, while the underlying threat (covert interception/manipulation of communications between trusting parties) remains the same.",optionExplanations:["This is a network/cyber attack describing logical positioning in a data path, not physical transportation routes.","On-path attacks fundamentally rely on the attacker successfully positioning themselves within the legitimate communication flow, allowing covert interception or manipulation that breaks the assumed direct trust between the two communicating endpoints.","On-path positioning describes a malicious attack vector, not a legitimate network engineering/optimization technique.","'Mail' here refers to network/data communications, not literal postal services — this is simply updated terminology for MITM attacks."]},
  {id:859,domain:A,question:"What is the purpose of network segmentation between IT and OT (Operational Technology) environments?",options:["Segmentation purely for organizational chart purposes","Isolating industrial control systems and operational technology (which often run legacy, unpatched systems controlling physical processes) from the corporate IT network, limiting the ability of an IT compromise to spread into critical infrastructure", "Segmentation that has no security benefit, only cost benefit","A practice that is illegal under most industrial regulations"],answer:1,explanation:"The 2021 Colonial Pipeline incident demonstrated the risk when IT/OT separation is insufficient — though the OT systems weren't directly compromised, the company proactively shut down pipeline operations due to IT compromise concerns, highlighting how IT/OT segmentation (using firewalls, data diodes, and the Purdue Model architecture) is critical since OT systems often can't be patched/secured the same way as IT systems due to uptime and safety requirements.",optionExplanations:["This is a critical technical security control protecting physical/industrial processes, not merely an organizational structure designation.","IT/OT segmentation is increasingly recognized as essential given that OT systems often run unpatched legacy software controlling physical, safety-critical processes — limiting blast radius from IT-side compromises is a primary defense given OT's inherent patching limitations.","IT/OT segmentation provides substantial security benefit beyond cost, directly protecting critical infrastructure and safety systems from cyber-originated disruption.","Proper segmentation is generally a recommended and often required practice (e.g., NERC CIP for power utilities), not an illegal one."]},
  {id:860,domain:O,question:"What is the purpose of a security metrics dashboard for executive reporting?",options:["A dashboard showing only individual analyst performance reviews","A visual reporting tool that translates technical security data into business-relevant metrics and trends (e.g., risk exposure, patch compliance, incident trends) to help executives understand security posture and make informed resource allocation decisions","A dashboard used only by the marketing department","A tool for tracking employee vacation schedules"],answer:1,explanation:"Effective executive dashboards avoid overwhelming leadership with raw technical detail (like CVE counts) and instead present trends and business risk context (e.g., 'critical vulnerability remediation time has decreased 40% this quarter, but third-party vendor risk remains elevated') — this enables non-technical executives to understand security posture and make informed budget/risk decisions.",optionExplanations:["Executive dashboards focus on aggregate organizational security posture and risk, not individual employee performance evaluation.","Translating technical data into business-relevant context is essential for executive engagement and informed decision-making, since most executives lack the technical background to interpret raw security metrics directly.","Security dashboards serve security/risk governance purposes for leadership, unrelated to marketing department functions.","Vacation tracking is an HR/operational function, unrelated to security posture reporting."]},
  {id:861,domain:T,question:"What is a cryptojacking attack?",options:["An attack that steals cryptocurrency wallet files directly","Unauthorized use of a victim's computing resources (CPU/GPU) to mine cryptocurrency, often delivered via malware or malicious browser scripts, without the victim's knowledge or consent","A legitimate cryptocurrency mining service offered by cloud providers","An attack that encrypts cryptocurrency exchanges for ransom"],answer:1,explanation:"Cryptojacking malware or malicious JavaScript (running in a compromised website) silently consumes victim CPU/GPU resources to mine cryptocurrency for the attacker's benefit — symptoms include unexplained high CPU usage, system slowdown, and increased electricity costs; while less immediately destructive than ransomware, it represents unauthorized resource theft and can indicate broader compromise.",optionExplanations:["Cryptojacking abuses computing resources for mining rather than directly stealing existing wallet contents (which would be a different attack like wallet credential theft).","Cryptojacking is attractive to attackers because it's relatively low-risk/low-detection compared to more disruptive attacks like ransomware, generating ongoing passive income by quietly stealing victim compute resources.","Legitimate cloud mining services involve explicit consent and payment; cryptojacking is defined by its unauthorized, covert nature.","This describes unauthorized resource theft for mining, not a ransomware-style encryption attack against exchange infrastructure."]},
  {id:862,domain:G,question:"What is the purpose of the principle of 'fail securely' (fail closed) in system design?",options:["Designing systems to never fail under any circumstances","Designing systems so that when a failure occurs (e.g., authentication service outage), the default behavior denies access rather than granting it, prioritizing security over availability in failure scenarios","Designing systems to fail as quickly and visibly as possible regardless of consequences","Allowing all access automatically whenever any system component fails"],answer:1,explanation:"A fail-secure access control system that loses connection to its authentication server should default to denying entry (even if inconvenient) rather than failing 'open' and granting unrestricted access — though this principle must be balanced against safety-critical systems (like fire door locks) where failing open may be required for life safety, illustrating the security-vs-safety tradeoff designers must navigate.",optionExplanations:["No system can guarantee zero failures; the design principle addresses how the system behaves WHEN failure occurs, not preventing all failure.","Fail-secure design accepts a potential availability tradeoff (denying access during failure) in exchange for maintaining the security posture, recognizing that most failures should default toward the safer, more restrictive state.","While failures should be detected/logged, 'fail securely' specifically concerns the access decision outcome during failure, not failure visibility/speed for its own sake.","This describes 'fail open,' essentially the opposite of fail-secure design, which would create a significant security gap during any failure event."]},
  {id:863,domain:O,question:"What is the purpose of conducting a gap analysis against a security framework (e.g., NIST CSF)?",options:["Analyzing physical gaps in server room flooring","Comparing an organization's current security practices and controls against a chosen framework's requirements to identify deficiencies, prioritize remediation efforts, and guide a roadmap toward compliance or maturity improvement","An analysis used only during initial company formation","A one-time analysis that never needs to be repeated"],answer:1,explanation:"A gap analysis against NIST CSF's five functions (Identify, Protect, Detect, Respond, Recover) might reveal that an organization has strong 'Protect' controls (firewalls, access control) but weak 'Detect' and 'Respond' capabilities (no SIEM, undefined IR plan) — this informs where to prioritize investment to achieve more balanced, comprehensive security maturity.",optionExplanations:["This is a security program maturity assessment, unrelated to physical building infrastructure.","Gap analyses provide a structured, prioritized roadmap for security improvement by clearly identifying where current practices fall short of a recognized framework's requirements, guiding resource allocation.","Gap analyses are valuable at any organizational maturity stage, not just during initial formation, particularly as frameworks and threats evolve.","Security frameworks and organizational environments evolve continuously, requiring periodic re-assessment to maintain an accurate, current view of the security gap."]},
  {id:864,domain:T,question:"What is a replay attack?",options:["An attack that physically replays recorded video surveillance footage","An attack where a valid data transmission (such as an authentication token or transaction) is fraudulently intercepted and retransmitted later to gain unauthorized access or repeat a transaction", "A method for backing up and replaying database transactions for testing","A type of legitimate session resumption mechanism"],answer:1,explanation:"If a system doesn't use proper anti-replay measures (timestamps, nonces, sequence numbers), an attacker who intercepts a legitimate authentication request or financial transaction can simply resend that exact same captured data later to be authenticated or repeat the transaction fraudulently — defenses include timestamping requests, using single-use nonces, and implementing short validity windows for tokens.",optionExplanations:["This is a network/cryptographic attack on data transmissions, unrelated to video surveillance footage.","Replay attacks specifically exploit the absence of freshness/uniqueness verification in transmitted data — proper anti-replay mechanisms (nonces, timestamps, sequence numbers) are essential defenses in authentication and transaction protocols.","This describes a legitimate testing/development practice, the opposite of the malicious unauthorized retransmission attack.","Legitimate session resumption uses proper cryptographic protocols with freshness guarantees; replay attacks specifically exploit the lack of such protections to maliciously reuse captured data."]},
  {id:865,domain:A,question:"What is the purpose of implementing application allowlisting (whitelisting)?",options:["Maintaining a list of websites employees are allowed to visit only","A security control that only permits pre-approved, explicitly authorized applications/executables to run on a system, blocking all others by default, providing strong protection against unknown malware and unauthorized software","A list of approved vendors for purchasing software","A backup list of applications to reinstall after a system wipe"],answer:1,explanation:"Unlike blocklisting (denying known-bad applications, which fails against new/unknown threats), allowlisting (using tools like AppLocker or Windows Defender Application Control) takes a default-deny stance — only explicitly approved applications can execute, providing strong protection against zero-day malware and unauthorized software installation, though it requires more administrative overhead to maintain the approved list as legitimate software needs change.",optionExplanations:["Website allowlisting (URL filtering) is a related but distinct control; application allowlisting specifically governs which executables/programs can run on the endpoint.","Application allowlisting's default-deny approach is particularly effective against zero-day and unknown malware, since unrecognized executables simply can't run, regardless of whether security tools have signatures for them yet.","Vendor approval lists are a procurement/business process, distinct from the technical endpoint control of restricting executable execution.","Allowlisting is an active, ongoing execution control, not a backup/recovery list for reinstallation purposes."]},
  {id:866,domain:O,question:"What is the purpose of conducting a tabletop exercise specifically focused on ransomware scenarios?",options:["Testing only the physical security of the data center against ransomware","Simulating a ransomware incident scenario in a discussion-based format to test the organization's decision-making, communication, and technical response procedures, including critical decisions like whether to pay a ransom","A marketing exercise to sell ransomware insurance products","A technical exercise that actually deploys ransomware on production systems"],answer:1,explanation:"Ransomware tabletop exercises walk through difficult decisions in advance — who has authority to decide on ransom payment, how to communicate with customers/regulators during an outage, whether cyber insurance covers the incident, and how to determine if backups are viable for recovery — making these decisions calmly beforehand is far more effective than improvising during an actual, high-pressure ransomware crisis.",optionExplanations:["Ransomware tabletops focus on organizational decision-making and procedural response, not physical building security testing.","Ransomware scenarios involve uniquely difficult decisions (ransom payment, regulatory notification, business continuity tradeoffs) that benefit enormously from being pre-discussed and planned for in a low-stakes tabletop setting.","Tabletop exercises are internal organizational preparedness activities, not externally-facing sales/marketing activities.","Tabletop exercises are explicitly discussion-based simulations, never involving actual deployment of malware on live systems."]},
  {id:867,domain:T,question:"What is a credential harvesting attack?",options:["A legitimate process for collecting employee feedback","An attack technique, often via phishing pages or compromised systems, specifically designed to collect usernames, passwords, or other authentication credentials from victims for later malicious use", "A method for backing up password databases securely","An attack that physically removes RFID badges"],answer:1,explanation:"Credential harvesting phishing pages mimic legitimate login portals (Office 365, banking sites) to capture entered credentials, which are then used for account takeover, sold on dark web markets, or used as a foothold for further attacks like credential stuffing against other services — harvested credentials are among the most valuable and commonly traded commodities in cybercrime.",optionExplanations:["This describes a malicious data theft technique, not a legitimate organizational feedback collection process.","Credential harvesting is often the explicit goal of phishing campaigns, since stolen credentials provide direct, persistent access value that can be monetized or leveraged for further attacks far beyond the initial compromise.","This isn't a secure backup process; it's an unauthorized theft technique targeting authentication data.","This is a digital data theft attack, not a physical badge/token theft technique."]},
  {id:868,domain:P,question:"What is the purpose of obtaining cyber liability insurance?",options:["Insurance that replaces the need for any technical security controls","A specialized insurance policy that helps organizations financially mitigate the costs associated with a cyber incident, such as breach response, legal fees, regulatory fines, and business interruption losses", "Insurance covering only physical hardware damage from fire or flood","A policy required for all employees individually to purchase"],answer:1,explanation:"Cyber insurance can cover costs like forensic investigation, customer notification, credit monitoring services, legal defense, and even ransom payments in some policies — however, insurers increasingly require evidence of baseline security controls (MFA, EDR, backups) as a condition of coverage, recognizing that insurance complements rather than replaces actual security investment.",optionExplanations:["Insurers increasingly require demonstrable security controls as a prerequisite for coverage, and insurance addresses financial impact, not the technical prevention of incidents themselves.","Cyber insurance specifically addresses the financial consequences of cyber incidents, complementing (not replacing) technical and procedural security controls that reduce the likelihood and impact of incidents in the first place.","This is a distinct risk category from traditional property insurance covering physical disasters; cyber insurance specifically addresses digital/data-related incidents.","This is an organizational-level policy covering the company's risk exposure, not an individual employee purchase requirement."]},
  {id:869,domain:A,question:"What is the purpose of implementing DNS filtering as a security control?",options:["Filtering DNS purely to improve resolution speed","Blocking access to known malicious, phishing, or otherwise inappropriate domains at the DNS resolution level, preventing devices from connecting to these destinations even before a network connection is established","A backup mechanism for DNS server failure","A method exclusively for blocking competitor websites"],answer:1,explanation:"DNS filtering services (Cisco Umbrella, Cloudflare Gateway) maintain threat intelligence feeds of known malicious domains and block resolution requests to them — this provides an early, low-overhead layer of defense since malware often needs to resolve a C2 domain to communicate, and blocking that resolution can neutralize the threat before any actual malicious traffic is established.",optionExplanations:["While performance can be a side benefit, the primary security purpose is blocking malicious destinations, not speed optimization.","DNS filtering provides defense at an efficient layer — blocking resolution prevents connection attempts to malicious infrastructure before any actual malicious payload delivery or C2 communication can occur.","DNS filtering is an active security control providing ongoing protection, not a failover/backup mechanism for DNS infrastructure outages.","Legitimate DNS filtering targets known-malicious or policy-violating categories of content, not business competitor blocking, which would raise ethical and likely legal concerns."]},
  {id:870,domain:O,question:"What is the purpose of conducting a controlled phishing simulation campaign?",options:["A campaign designed to actually steal employee credentials for management review","Sending simulated, harmless phishing emails to employees to measure susceptibility, reinforce security awareness training, and identify individuals or departments needing additional targeted education","A campaign used only to punish employees who click on links","A one-time test with no ongoing program or follow-up"],answer:1,explanation:"Effective phishing simulation programs (using platforms like KnowBe4 or Proofpoint) track click rates over time, provide immediate just-in-time training for employees who click (rather than punitive action), and use results to identify patterns (e.g., a specific department needs additional training) — the goal is behavior change and awareness improvement, not punishment or credential theft.",optionExplanations:["Simulated phishing campaigns don't actually steal/retain credentials maliciously; they're a controlled training tool, and any captured test data is used for improvement, not retention.","Phishing simulations directly measure and improve the human element of security, identifying training gaps so resources can be targeted effectively at the employees/departments most in need.","Best practice phishing simulation programs use clicking as a learning opportunity (just-in-time training) rather than punitive measures, which research shows discourages honest reporting of real phishing attempts.","Effective programs run phishing simulations regularly (not just once) to reinforce ongoing awareness and track improvement trends over time."]},
  {id:871,domain:T,question:"What is a Bluetooth bluejacking attack?",options:["A severe attack that completely takes over and disables a Bluetooth device","Sending unsolicited messages or files to Bluetooth-enabled devices within range, often as a nuisance or minor prank rather than a serious security threat, distinct from more dangerous Bluetooth attacks like bluesnarfing","A legitimate Bluetooth pairing notification system","An attack that physically disables Bluetooth hardware chips"],answer:1,explanation:"Bluejacking is relatively low-risk — typically just sending unsolicited contact cards or text messages to nearby discoverable devices — and is distinct from bluesnarfing (unauthorized data theft from a Bluetooth device) or bluebugging (gaining full unauthorized control), which are far more serious security threats.",optionExplanations:["This describes bluebugging (full device takeover), a much more serious attack than the relatively minor nuisance of bluejacking.","Bluejacking is generally categorized as a low-severity nuisance attack, important to distinguish from the more serious data theft (bluesnarfing) and device control (bluebugging) Bluetooth attack variants for exam purposes.","Bluejacking is unauthorized/unsolicited, not a legitimate notification feature, though it's relatively benign compared to other Bluetooth attacks.","Bluejacking doesn't damage hardware; it's about sending unsolicited messages, not physical/hardware-level attacks."]},
  {id:872,domain:A,question:"What is the purpose of a software-defined perimeter (SDP) architecture?",options:["A perimeter defined purely by physical building boundaries","A security framework that dynamically creates individualized, encrypted network connections between authenticated/authorized users and specific resources, making infrastructure invisible to unauthorized users ('black cloud') and aligning closely with zero trust principles","A perimeter that only protects against physical intrusion","A backup network perimeter used during primary firewall failure"],answer:1,explanation:"SDP (sometimes called a 'black cloud' approach) verifies user identity and device posture before granting access, then creates a direct, encrypted micro-tunnel to only the specific authorized resource — unlike traditional perimeter security, unauthorized users can't even see that protected resources exist on the network (no open ports visible to port scanning), significantly reducing the attack surface.",optionExplanations:["SDP is a logical/software network security architecture, not defined by physical building boundaries.","SDP fundamentally shifts away from traditional 'trusted network perimeter' models toward identity-centric, resource-specific dynamic access — directly implementing zero trust principles by making unauthorized resources invisible rather than just access-restricted.","SDP addresses network/logical access security, a different scope from physical intrusion prevention.","SDP is a primary, ongoing security architecture approach, not merely a failover/backup mechanism for traditional firewalls."]},
  {id:873,domain:O,question:"What is the purpose of implementing automated security orchestration playbooks for phishing response?",options:["Playbooks used only for musical performances in the SOC","Pre-defined, automated workflows that handle common phishing response steps (quarantining the email, checking for clicks, resetting credentials if needed, blocking the sender) without requiring manual analyst intervention for each step, improving response speed and consistency","A backup procedure used only when SOAR tools are unavailable","A playbook requiring full manual execution with no automation"],answer:1,explanation:"A SOAR phishing playbook might automatically pull the email's headers and attachments for analysis, check if any other users received the same email and auto-quarantine those copies, query EDR to see if any recipients clicked the link, and auto-create a ticket — reducing response time from potentially hours of manual work to minutes, and ensuring consistent handling regardless of which analyst (or shift) is working.",optionExplanations:["This is wordplay; security playbooks have nothing to do with music.","Automated phishing playbooks significantly reduce response time and ensure consistency for high-volume, well-understood incident types, freeing analyst time for more complex investigations.","Playbooks are the primary automated workflow itself within SOAR tools, not a fallback used only in their absence.","The defining value of these playbooks is automation of repetitive steps; fully manual execution would defeat their core purpose of speed and consistency."]},
  {id:874,domain:T,question:"What is a watering hole attack's primary advantage for attackers compared to direct phishing?",options:["It requires no technical skill whatsoever to execute","It can compromise well-defended, security-aware targets who would be unlikely to fall for direct phishing attempts, by exploiting their trust in legitimate third-party websites they routinely visit","It is always faster to execute than sending a phishing email","It guarantees compromise of every visitor to the compromised site"],answer:1,explanation:"Watering hole attacks are particularly valuable against sophisticated targets (security researchers, government employees, defense contractors) who have strong security awareness and would likely recognize/report a direct phishing attempt — by compromising a trusted third-party site instead, attackers bypass the target's heightened suspicion of direct communications.",optionExplanations:["Watering hole attacks actually require significant technical skill — compromising a legitimate third-party website and often deploying browser exploits is considerably more complex than crafting a phishing email.","This advantage is precisely why APT groups favor watering hole attacks against high-value, security-conscious targets — it circumvents their learned suspicion of direct phishing by exploiting trust in already-visited legitimate sites.","Watering hole attacks require time-intensive reconnaissance (identifying target browsing habits) and site compromise, typically making them slower to set up than a phishing campaign.","Success depends on the victim having a vulnerable, unpatched browser/plugin and visiting during the attack window — it's not guaranteed for every visitor, especially those with updated, patched systems."]},
  {id:875,domain:G,question:"What is the purpose of implementing a 'defense in depth' security strategy?",options:["Relying on a single, extremely strong security control instead of multiple layers","Implementing multiple, layered, and redundant security controls throughout a system so that if one control fails or is bypassed, additional controls still provide protection", "A strategy focused exclusively on perimeter firewall strength","A cost-cutting strategy that minimizes the total number of security controls"],answer:1,explanation:"A defense-in-depth approach for a database might include network segmentation, a firewall, an IPS, strong authentication, encryption at rest, database activity monitoring, and regular access reviews — even if an attacker bypasses the firewall, they still face multiple additional obstacles, unlike a single-point-of-failure approach where one bypassed control means complete compromise.",optionExplanations:["This describes the opposite approach; defense in depth specifically avoids single points of failure by layering multiple independent controls.","Defense in depth's core value is resilience — since no single control is perfect, layering ensures that a failure or bypass of one control doesn't result in complete compromise, requiring attackers to overcome multiple independent obstacles.","Defense in depth spans the entire environment (network, host, application, data, physical, human), not solely the network perimeter.","Defense in depth often requires more investment in multiple controls, not cost reduction — it's a security effectiveness strategy, not primarily a budget optimization one."]},
  {id:876,domain:O,question:"What is the purpose of measuring and tracking 'dwell time' as a security metric?",options:["Measuring how long employees stay at their desks","Measuring the length of time an attacker remains undetected within a network from initial compromise to detection, with shorter dwell time generally indicating more effective detection capabilities and reduced potential damage","Measuring server response time for customer-facing applications","Measuring how long security tickets sit unassigned in a queue"],answer:1,explanation:"Industry dwell time averages have decreased over recent years due to improved detection technology (EDR, better SIEM analytics) but can still range from days to many months for sophisticated attacks — every additional day of undetected dwell time generally correlates with increased opportunity for data exfiltration, lateral movement, and overall breach impact, making dwell time reduction a key security program objective.",optionExplanations:["This is an HR/workplace metric, unrelated to detecting attacker presence in systems.","Dwell time is one of the most impactful security metrics because it directly correlates with breach severity — every day an attacker operates undetected typically increases the scope of compromise, data theft, and remediation cost.","Application performance metrics are operational/IT metrics, distinct from the security-specific concept of attacker dwell time.","Ticket queue time is an operational efficiency metric, different from the security concept of measuring attacker presence duration before detection."]},
  {id:877,domain:T,question:"What is a UDP flood attack?",options:["A legitimate stress test for UDP-based applications","A denial-of-service attack that overwhelms a target with a high volume of UDP packets sent to random ports, forcing the target to repeatedly check for listening applications and respond with ICMP 'destination unreachable' packets, consuming resources","An attack that exploits a vulnerability specific to TCP connections only","A method for compressing UDP packet headers"],answer:1,explanation:"Because UDP is connectionless (no handshake required like TCP), attackers can rapidly send massive volumes of spoofed UDP packets without needing to complete any negotiation — the target system's resource consumption checking each port and generating responses, combined with the connectionless nature making source verification difficult, makes UDP floods a common and effective volumetric DoS technique.",optionExplanations:["This is an unauthorized, malicious attack technique, not an authorized stress testing methodology.","UDP floods exploit the protocol's connectionless nature — no handshake is required, allowing attackers to send overwhelming traffic volumes quickly while the target expends resources processing each packet and generating unreachable responses.","UDP floods specifically target UDP's connectionless protocol characteristics; TCP-based attacks (like SYN floods) exploit different protocol mechanics.","This is a denial-of-service attack technique, unrelated to data compression/optimization."]},
  {id:878,domain:A,question:"What is the purpose of implementing just-in-time (JIT) access provisioning?",options:["Provisioning access only during specific calendar holidays","Granting users elevated or privileged access only for the specific time window needed to complete a task, automatically revoking that access afterward, rather than maintaining standing privileged access indefinitely","A backup access method used only during system outages","A method for speeding up new employee onboarding regardless of security review"],answer:1,explanation:"JIT access (implemented via PAM solutions like CyberArk or Azure PIM) significantly reduces the standing attack surface — instead of an admin having permanent domain admin rights that could be compromised at any time, they request elevated access for a specific task, it's granted temporarily (e.g., 2 hours) with approval and logging, then automatically revoked, minimizing the window during which those credentials pose risk if compromised.",optionExplanations:["JIT access is about minimizing the duration of privilege regardless of calendar timing, not tied to specific holiday periods.","JIT access directly supports least privilege and zero standing privilege principles by minimizing the time window during which elevated credentials exist and could be compromised or misused.","JIT is a standard, ongoing privileged access management practice, not specifically an outage/emergency access mechanism.","JIT specifically refers to temporary privilege elevation with proper approval workflows, not a shortcut that bypasses security review during onboarding."]},
  {id:879,domain:O,question:"What is the purpose of an incident response communication plan?",options:["A plan that only covers internal Slack/Teams messaging etiquette","A predefined plan detailing who needs to be informed during an incident, what information to share, through which channels, and at what cadence — covering internal stakeholders, customers, regulators, and potentially media/public relations","A plan for setting up new employee email accounts","A marketing communication plan unrelated to security"],answer:1,explanation:"Communication plans prevent costly mistakes during high-pressure incidents — like a well-meaning employee posting incident details on social media before legal/PR has prepared an official statement, or missing a regulatory breach notification deadline (e.g., GDPR's 72-hour requirement) due to unclear ownership of that responsibility.",optionExplanations:["Communication plans address all critical incident stakeholders and channels, not solely internal collaboration tool conventions.","Comprehensive communication planning prevents both under-communication (missing required regulatory notifications, leaving customers uninformed) and over-communication (premature or unauthorized disclosure) during high-stress incident scenarios.","Email account provisioning is an IT operations task, unrelated to incident communication planning.","Incident communication plans are specifically security/crisis-focused, distinct from general business marketing communications."]},
  {id:880,domain:T,question:"What is a wireless jamming attack?",options:["An attack that improves wireless signal strength for legitimate users","A denial-of-service attack that transmits interfering radio frequency signals to disrupt or block legitimate wireless communications, preventing devices from establishing or maintaining a connection","A legitimate technique for testing wireless coverage","An attack requiring direct physical access to network cables"],answer:1,explanation:"Jamming attacks flood the same frequency spectrum used by WiFi (2.4GHz/5GHz) or other wireless protocols with noise/interference, denying service to legitimate users — unlike most cyberattacks, jamming requires physical proximity to the target's RF range and specialized equipment, and is illegal in most jurisdictions under telecommunications regulations regardless of intent.",optionExplanations:["Jamming degrades or completely denies legitimate wireless service through RF interference, the opposite of improving connectivity.","Jamming attacks exploit the shared, contested nature of RF spectrum — by flooding the relevant frequency with noise, legitimate devices cannot successfully transmit or receive, causing a denial of service specific to wireless communications.","Jamming is an unauthorized, illegal disruption technique, not a legitimate coverage testing methodology (which would use a spectrum analyzer instead).","Jamming requires physical proximity within RF range of the target but doesn't require accessing or touching network cables; it operates purely through radio frequency interference."]},
  {id:881,domain:G,question:"What is the purpose of a security policy exception review board or governance committee?",options:["A board that approves only employee vacation requests","A governing body of stakeholders that reviews and approves significant security policy exceptions, risk acceptances, and major security decisions, ensuring appropriate oversight and cross-functional input","A committee that only handles physical building maintenance","A board that operates independently with no accountability to executive leadership"],answer:1,explanation:"Governance committees (often including representatives from security, legal, IT, and business units) provide checks and balances for significant risk decisions — preventing any single individual from unilaterally accepting major organizational risk, and ensuring decisions consider multiple perspectives (legal liability, business impact, technical feasibility) before approval.",optionExplanations:["This is a security risk governance function, unrelated to HR vacation approval processes.","Governance committees provide essential cross-functional oversight for significant security risk decisions, preventing unilateral risk acceptance and ensuring decisions are well-informed and accountable across the organization.","Security governance committees address policy and risk decisions broadly, not narrowly focused on physical facilities.","Governance committees typically report to and are accountable to executive leadership/the board, providing a structured escalation and accountability path, not operating in isolation."]},
  {id:882,domain:O,question:"What is the purpose of conducting a forensic memory (RAM) capture during incident response?",options:["Capturing memory only to free up disk space","Preserving the volatile contents of a system's RAM, which can contain critical evidence like running processes, network connections, encryption keys, and malware that exists only in memory (fileless malware) and would be lost upon system shutdown","A routine backup procedure performed on a daily schedule","A technique used only to test hardware memory for defects"],answer:1,explanation:"Memory is volatile — its contents are lost the moment a system powers off — making memory capture (using tools like FTK Imager or Volatility for analysis) critical for capturing evidence of fileless malware, active malicious processes, or decryption keys that would never be discoverable from a disk image alone, which is why proper IR procedure often calls for memory capture before any system shutdown.",optionExplanations:["Memory capture is for forensic evidence preservation, not a storage management technique.","Memory capture is uniquely time-sensitive and valuable because volatile data (running processes, network state, in-memory malware, encryption keys) is irretrievably lost once a system is powered off, unlike persistent disk-based evidence.","Memory capture during IR is an as-needed forensic procedure tied to active investigations, not a routine scheduled backup process.","This is a security forensic technique for evidence preservation, not hardware diagnostic testing."]},
];
